const CELLS_GOLD_50_HEALTHCARE_KPIS: NotebookCell[] = [
  {
    "id": "gold-50-healthcare-kpis-c0",
    "type": "markdown",
    "source": "# Gold Layer: Healthcare Operational KPIs\n\nComputes hospital performance metrics from Silver healthcare encounters.\n\n## KPIs Calculated\n- **Readmission Rate** (30-day, by DRG and payer)\n- **Average LOS** (by DRG, payer, disposition)\n- **ED-to-Admit Time** (median and P90)\n- **Bed Occupancy Rate** (daily)\n- **Denial Rate** (by payer)\n- **Case Mix Index** (CMI)\n\n## Target Tables\n- `gold_healthcare_kpis` - Aggregated operational metrics\n- `gold_healthcare_readmission_risk` - Patient-level readmission risk"
  },
  {
    "id": "gold-50-healthcare-kpis-c1",
    "type": "markdown",
    "source": "## Configuration"
  },
  {
    "id": "gold-50-healthcare-kpis-c2",
    "type": "code",
    "source": "import os\nfrom datetime import datetime\n\nfrom delta.tables import DeltaTable\nfrom pyspark.sql.functions import (\n    avg,\n    coalesce,\n    col,\n    count,\n    countDistinct,\n    current_timestamp,\n    expr,\n    lit,\n    max,\n    min,\n    percentile_approx,\n    round as spark_round,\n    sum,\n    when,\n)\n\n\ndef _get_arg(name: str, default=None):\n    \"\"\"Read a notebook parameter from Fabric/Synapse runtime, env var, or default.\"\"\"\n    try:\n        import notebookutils\n        return notebookutils.notebook.getArgument(name, default)\n    except Exception:\n        try:\n            import mssparkutils\n            return mssparkutils.notebook.getArgument(name, default)\n        except Exception:\n            return os.environ.get(name.upper(), default)\n\n\nbatch_id = _get_arg(\"batch_id\", datetime.now().strftime(\"%Y%m%d_%H%M%S\"))\n\nsource_table = \"lh_silver.dbo.silver_healthcare_encounters\"\ntarget_kpis = \"lh_gold.dbo.gold_healthcare_kpis\"\ntarget_readmit = \"lh_gold.dbo.gold_healthcare_readmission_risk\"\n\n# CMS DRG weights (simplified top-10 for CMI calculation)\nDRG_WEIGHTS = {\n    \"871\": 5.41, \"872\": 3.21, \"470\": 1.91, \"291\": 1.64, \"292\": 0.98,\n    \"193\": 1.43, \"194\": 0.91, \"689\": 1.14, \"690\": 0.72, \"065\": 3.87,\n}\nDEFAULT_DRG_WEIGHT = 1.00\n\nTOTAL_BEDS = 350  # configurable hospital bed count\n\nprint(f\"Batch: {batch_id}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-50-healthcare-kpis-c3",
    "type": "markdown",
    "source": "## Read Silver Data"
  },
  {
    "id": "gold-50-healthcare-kpis-c4",
    "type": "code",
    "source": "df = spark.table(source_table)\nprint(f\"Silver records: {df.count():,}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-50-healthcare-kpis-c5",
    "type": "markdown",
    "source": "## KPI 1: Aggregate Metrics by DRG"
  },
  {
    "id": "gold-50-healthcare-kpis-c6",
    "type": "code",
    "source": "df_by_drg = df.groupBy(\"drg_code\").agg(\n    count(\"*\").alias(\"encounters\"),\n    spark_round(avg(\"los_calc\"), 2).alias(\"avg_los\"),\n    spark_round(avg(when(col(\"readmit_30d\") == 1, 1).otherwise(0)) * 100, 2).alias(\"readmit_rate_pct\"),\n    countDistinct(\"mrn_hash\").alias(\"unique_patients\"),\n    spark_round(avg(\"_dq_score\"), 1).alias(\"avg_quality\"),\n)",
    "lang": "pyspark"
  },
  {
    "id": "gold-50-healthcare-kpis-c7",
    "type": "markdown",
    "source": "## KPI 2: Payer Analysis & Denial Rate"
  },
  {
    "id": "gold-50-healthcare-kpis-c8",
    "type": "code",
    "source": "df_by_payer = df.groupBy(\"payer\").agg(\n    count(\"*\").alias(\"encounters\"),\n    spark_round(avg(\"los_calc\"), 2).alias(\"avg_los\"),\n    spark_round(avg(when(col(\"readmit_30d\") == 1, 1).otherwise(0)) * 100, 2).alias(\"readmit_rate_pct\"),\n)",
    "lang": "pyspark"
  },
  {
    "id": "gold-50-healthcare-kpis-c9",
    "type": "markdown",
    "source": "## KPI 3: ED-to-Admit Time"
  },
  {
    "id": "gold-50-healthcare-kpis-c10",
    "type": "code",
    "source": "df_ed_metrics = df.filter(col(\"ed_to_admit_minutes\").isNotNull()).agg(\n    spark_round(avg(\"ed_to_admit_minutes\"), 1).alias(\"avg_ed_to_admit_min\"),\n    spark_round(percentile_approx(\"ed_to_admit_minutes\", 0.5), 1).alias(\"median_ed_to_admit_min\"),\n    spark_round(percentile_approx(\"ed_to_admit_minutes\", 0.9), 1).alias(\"p90_ed_to_admit_min\"),\n    count(\"*\").alias(\"ed_encounters\"),\n)",
    "lang": "pyspark"
  },
  {
    "id": "gold-50-healthcare-kpis-c11",
    "type": "markdown",
    "source": "## KPI 4: Daily Bed Occupancy"
  },
  {
    "id": "gold-50-healthcare-kpis-c12",
    "type": "code",
    "source": "df_daily_census = df.groupBy(\"admit_date\").agg(\n    count(\"*\").alias(\"admissions\"),\n    spark_round(count(\"*\") / lit(TOTAL_BEDS) * 100, 2).alias(\"occupancy_rate_pct\"),\n    spark_round(avg(\"los_calc\"), 2).alias(\"avg_los\"),\n    sum(when(col(\"readmit_30d\") == 1, 1).otherwise(0)).alias(\"readmissions\"),\n)",
    "lang": "pyspark"
  },
  {
    "id": "gold-50-healthcare-kpis-c13",
    "type": "markdown",
    "source": "## KPI 5: Case Mix Index"
  },
  {
    "id": "gold-50-healthcare-kpis-c14",
    "type": "code",
    "source": "from pyspark.sql.functions import udf\nfrom pyspark.sql.types import DoubleType\n\n@udf(DoubleType())\ndef drg_weight_udf(drg_code):\n    if drg_code is None:\n        return float(DEFAULT_DRG_WEIGHT)\n    return float(DRG_WEIGHTS.get(str(drg_code), DEFAULT_DRG_WEIGHT))\n\ndf_cmi = df.withColumn(\"drg_weight\", drg_weight_udf(col(\"drg_code\")))\ncmi_value = df_cmi.agg(spark_round(avg(\"drg_weight\"), 4).alias(\"case_mix_index\")).collect()[0][0]\nprint(f\"Case Mix Index: {cmi_value}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-50-healthcare-kpis-c15",
    "type": "markdown",
    "source": "## Build Combined KPI Table"
  },
  {
    "id": "gold-50-healthcare-kpis-c16",
    "type": "code",
    "source": "# Combine DRG-level metrics with overall stats\ndf_kpi_combined = df_by_drg \\\n    .withColumn(\"metric_type\", lit(\"by_drg\")) \\\n    .withColumn(\"case_mix_index\", lit(cmi_value)) \\\n    .withColumn(\"total_beds\", lit(TOTAL_BEDS)) \\\n    .withColumn(\"_gold_timestamp\", current_timestamp()) \\\n    .withColumn(\"_batch_id\", lit(batch_id))\n\ntry:\n    if spark.catalog.tableExists(target_kpis):\n        deltaTable = DeltaTable.forName(spark, target_kpis)\n        deltaTable.alias(\"target\").merge(\n            df_kpi_combined.alias(\"source\"),\n            \"target.drg_code = source.drg_code AND target.metric_type = source.metric_type\"\n        ).whenMatchedUpdateAll().whenNotMatchedInsertAll().execute()\n    else:\n        df_kpi_combined.write.format(\"delta\") \\\n            .mode(\"overwrite\") \\\n            .option(\"overwriteSchema\", \"true\") \\\n            .saveAsTable(target_kpis)\n\n    print(f\"Wrote KPIs to {target_kpis}\")\nexcept Exception as e:\n    print(f\"ERROR writing {target_kpis}: {e}\")\n    raise",
    "lang": "pyspark"
  },
  {
    "id": "gold-50-healthcare-kpis-c17",
    "type": "markdown",
    "source": "## Build Readmission Risk Table"
  },
  {
    "id": "gold-50-healthcare-kpis-c18",
    "type": "code",
    "source": "df_risk = df \\\n    .select(\n        \"encounter_id\", \"mrn_hash\", \"drg_code\", \"payer\",\n        \"los_calc\", \"readmit_30d\", \"days_since_last_discharge\",\n        \"age\", \"disposition\", \"ed_to_admit_minutes\",\n    ) \\\n    .withColumn(\"risk_score\",\n        (when(col(\"readmit_30d\") == 1, lit(40)).otherwise(lit(0))) +\n        (when(col(\"los_calc\") > 7, lit(15)).otherwise(lit(0))) +\n        (when(col(\"age\") > 65, lit(15)).otherwise(lit(0))) +\n        (when(col(\"disposition\").isin(\"SNF\", \"LTAC\", \"Rehab\"), lit(15)).otherwise(lit(0))) +\n        (when(col(\"ed_to_admit_minutes\") > 240, lit(15)).otherwise(lit(0)))\n    ) \\\n    .withColumn(\"risk_tier\",\n        when(col(\"risk_score\") >= 60, lit(\"HIGH\"))\n        .when(col(\"risk_score\") >= 30, lit(\"MEDIUM\"))\n        .otherwise(lit(\"LOW\"))\n    ) \\\n    .withColumn(\"_gold_timestamp\", current_timestamp()) \\\n    .withColumn(\"_batch_id\", lit(batch_id))\n\ntry:\n    if spark.catalog.tableExists(target_readmit):\n        deltaTable = DeltaTable.forName(spark, target_readmit)\n        deltaTable.alias(\"target\").merge(\n            df_risk.alias(\"source\"),\n            \"target.encounter_id = source.encounter_id\"\n        ).whenMatchedUpdateAll().whenNotMatchedInsertAll().execute()\n    else:\n        df_risk.write.format(\"delta\") \\\n            .mode(\"overwrite\") \\\n            .option(\"overwriteSchema\", \"true\") \\\n            .saveAsTable(target_readmit)\n\n    print(f\"Wrote readmission risk to {target_readmit}\")\nexcept Exception as e:\n    print(f\"ERROR writing {target_readmit}: {e}\")\n    raise",
    "lang": "pyspark"
  },
  {
    "id": "gold-50-healthcare-kpis-c19",
    "type": "markdown",
    "source": "## Optimize for Direct Lake"
  },
  {
    "id": "gold-50-healthcare-kpis-c20",
    "type": "code",
    "source": "spark.sql(f\"OPTIMIZE {target_kpis} ZORDER BY (drg_code)\")\nspark.sql(f\"OPTIMIZE {target_readmit} ZORDER BY (mrn_hash, risk_tier)\")\nprint(\"Gold tables optimized\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-50-healthcare-kpis-c21",
    "type": "markdown",
    "source": "## Validation Summary"
  },
  {
    "id": "gold-50-healthcare-kpis-c22",
    "type": "code",
    "source": "print(\"=== Healthcare KPI Summary ===\")\nspark.sql(f\"SELECT * FROM {target_kpis} ORDER BY encounters DESC LIMIT 10\").show(truncate=False)\n\nprint(f\"\\nCase Mix Index: {cmi_value}\")\nprint(f\"Total Beds: {TOTAL_BEDS}\")\n\nspark.sql(f\"\"\"\n    SELECT risk_tier, COUNT(*) as patients,\n           ROUND(AVG(risk_score), 1) as avg_score\n    FROM {target_readmit}\n    GROUP BY risk_tier ORDER BY avg_score DESC\n\"\"\").show()",
    "lang": "pyspark"
  },
  {
    "id": "gold-50-healthcare-kpis-c23",
    "type": "markdown",
    "source": "**Next Step:** Connect Gold tables to Power BI via Direct Lake for the Healthcare Operations dashboard."
  }
];

const CELLS_GOLD_51_FINANCIAL_FRAUD_SCORING: NotebookCell[] = [
  {
    "id": "gold-51-financial-fraud-scoring-c0",
    "type": "markdown",
    "source": "# Gold Layer: Financial Fraud Scoring & AML Alerts\n\nReads enriched Silver transactions and computes:\n1. **Fraud scores** - Rule-based + ML feature scoring per transaction\n2. **AML alerts** - CTR filings (>$10K) and structuring pattern detection\n3. **Daily fraud summary** - Aggregate fraud rate and loss metrics\n4. **Portfolio risk metrics** - Basel III risk-weighted asset approximations\n\n## Output Tables\n- `gold_fraud_scores` - Per-transaction fraud probability\n- `gold_aml_alerts` - BSA/AML alert queue\n- `gold_daily_fraud_summary` - Operational KPIs\n\n## Compliance\n- BSA/AML: 31 CFR 1010.311 (CTR threshold $10,000)\n- BSA/AML: 31 CFR 1010.314 (structuring detection)\n- SOX: Immutable audit trail in all Gold tables"
  },
  {
    "id": "gold-51-financial-fraud-scoring-c1",
    "type": "markdown",
    "source": "## Configuration"
  },
  {
    "id": "gold-51-financial-fraud-scoring-c2",
    "type": "code",
    "source": "from datetime import datetime\n\nfrom pyspark.sql import SparkSession, Window\nfrom pyspark.sql.functions import (\n    avg,\n    col,\n    count,\n    current_timestamp,\n    date_trunc,\n    greatest,\n    least,\n    lit,\n    round as spark_round,\n    sum as spark_sum,\n    to_date,\n    when,\n)\n\nspark = SparkSession.builder.getOrCreate()",
    "lang": "pyspark"
  },
  {
    "id": "gold-51-financial-fraud-scoring-c3",
    "type": "markdown",
    "source": "## Parameters"
  },
  {
    "id": "gold-51-financial-fraud-scoring-c4",
    "type": "code",
    "source": "SILVER_TABLE = \"lh_silver.silver_financial_enriched\"\nGOLD_FRAUD_SCORES = \"lh_gold.gold_fraud_scores\"\nGOLD_AML_ALERTS = \"lh_gold.gold_aml_alerts\"\nGOLD_DAILY_SUMMARY = \"lh_gold.gold_daily_fraud_summary\"\n\n# Compliance thresholds\nCTR_THRESHOLD = 10000.00  # 31 CFR 1010.311\nSTRUCTURING_LOW = 8000.00\nSTRUCTURING_HIGH = 9999.99\nSTRUCTURING_WINDOW_HOURS = 48",
    "lang": "pyspark"
  },
  {
    "id": "gold-51-financial-fraud-scoring-c5",
    "type": "markdown",
    "source": "## Read Silver Data"
  },
  {
    "id": "gold-51-financial-fraud-scoring-c6",
    "type": "code",
    "source": "df_silver = spark.read.format(\"delta\").table(SILVER_TABLE)\nprint(f\"Silver records read: {df_silver.count():,}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-51-financial-fraud-scoring-c7",
    "type": "markdown",
    "source": "## Fraud Scoring (Rule-Based)\n\nScore components (0-1 scale):\n- Velocity: >5 txns/1h → +0.25\n- Geo-anomaly: >500 km in <1h → +0.30\n- Amount spike: z-score >3 → +0.20\n- High-risk MCC → +0.15\n- Card-not-present (no 3DS) → +0.10"
  },
  {
    "id": "gold-51-financial-fraud-scoring-c8",
    "type": "code",
    "source": "df_scored = df_silver.withColumn(\n    \"score_velocity\",\n    when(col(\"txn_count_1h\") > 5, 0.25)\n    .when(col(\"txn_count_1h\") > 3, 0.10)\n    .otherwise(0.0),\n).withColumn(\n    \"score_geo\",\n    when(\n        (col(\"geo_distance_km\") > 500)\n        & (col(\"time_since_last_txn_sec\").isNotNull())\n        & (col(\"time_since_last_txn_sec\") < 3600),\n        0.30,\n    )\n    .when(col(\"geo_distance_km\") > 200, 0.10)\n    .otherwise(0.0),\n).withColumn(\n    \"score_amount\",\n    when(col(\"amount_zscore\") > 3.0, 0.20)\n    .when(col(\"amount_zscore\") > 2.0, 0.10)\n    .otherwise(0.0),\n).withColumn(\n    \"score_merchant\",\n    when(col(\"merchant_risk\") == \"high\", 0.15).otherwise(0.0),\n).withColumn(\n    \"score_channel\",\n    when(col(\"channel\") == \"card_not_present\", 0.10).otherwise(0.0),\n)\n\n# Composite fraud score (capped at 1.0)\ndf_scored = df_scored.withColumn(\n    \"fraud_score\",\n    least(\n        lit(1.0),\n        col(\"score_velocity\")\n        + col(\"score_geo\")\n        + col(\"score_amount\")\n        + col(\"score_merchant\")\n        + col(\"score_channel\"),\n    ),\n)\n\n# Decision\ndf_scored = df_scored.withColumn(\n    \"fraud_decision\",\n    when(col(\"fraud_score\") >= 0.85, \"DECLINE\")\n    .when(col(\"fraud_score\") >= 0.50, \"STEP_UP_AUTH\")\n    .otherwise(\"APPROVE\"),\n)",
    "lang": "pyspark"
  },
  {
    "id": "gold-51-financial-fraud-scoring-c9",
    "type": "markdown",
    "source": "## Write Fraud Scores"
  },
  {
    "id": "gold-51-financial-fraud-scoring-c10",
    "type": "code",
    "source": "fraud_output = df_scored.select(\n    \"txn_id\",\n    \"txn_ts\",\n    \"acct_id\",\n    \"card_hash\",\n    \"channel\",\n    \"merchant_name\",\n    \"merchant_mcc\",\n    \"amount\",\n    \"currency\",\n    \"is_fraud\",\n    \"fraud_pattern\",\n    \"fraud_score\",\n    \"fraud_decision\",\n    \"score_velocity\",\n    \"score_geo\",\n    \"score_amount\",\n    \"score_merchant\",\n    \"score_channel\",\n    \"txn_count_1h\",\n    \"geo_distance_km\",\n    \"amount_zscore\",\n    current_timestamp().alias(\"_scored_at\"),\n)\n\n(\n    fraud_output\n    .write\n    .format(\"delta\")\n    .mode(\"overwrite\")\n    .option(\"overwriteSchema\", \"true\")\n    .saveAsTable(GOLD_FRAUD_SCORES)\n)\n\nprint(f\"Fraud scores written: {fraud_output.count():,}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-51-financial-fraud-scoring-c11",
    "type": "markdown",
    "source": "## AML Alert Generation\n\n### CTR Filing (31 CFR 1010.311)\nAny cash transaction >= $10,000 requires a Currency Transaction Report.\n\n### Structuring Detection (31 CFR 1010.314)\nMultiple cash transactions between $8,000-$9,999 within 48 hours\nfrom the same customer."
  },
  {
    "id": "gold-51-financial-fraud-scoring-c12",
    "type": "code",
    "source": "# CTR Alerts\ndf_ctr = df_silver.filter(col(\"amount\") >= CTR_THRESHOLD).withColumn(\n    \"alert_type\", lit(\"CTR\")\n).withColumn(\n    \"alert_reason\",\n    lit(f\"Transaction amount >= ${CTR_THRESHOLD:,.2f} (31 CFR 1010.311)\"),\n).withColumn(\n    \"alert_priority\", lit(\"HIGH\")\n)\n\nprint(f\"CTR alerts: {df_ctr.count():,}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-51-financial-fraud-scoring-c13",
    "type": "code",
    "source": "# Structuring detection\nwindow_structuring = (\n    Window.partitionBy(\"acct_id\")\n    .orderBy(col(\"txn_ts\").cast(\"long\"))\n    .rangeBetween(-STRUCTURING_WINDOW_HOURS * 3600, 0)\n)\n\ndf_structuring_check = (\n    df_silver\n    .filter(\n        (col(\"amount\") >= STRUCTURING_LOW)\n        & (col(\"amount\") <= STRUCTURING_HIGH)\n    )\n    .withColumn(\n        \"structuring_count\",\n        count(\"txn_id\").over(window_structuring),\n    )\n    .filter(col(\"structuring_count\") >= 2)\n    .withColumn(\"alert_type\", lit(\"STRUCTURING\"))\n    .withColumn(\n        \"alert_reason\",\n        lit(f\"Multiple transactions ${STRUCTURING_LOW:,.0f}-${STRUCTURING_HIGH:,.0f} within {STRUCTURING_WINDOW_HOURS}h\"),\n    )\n    .withColumn(\"alert_priority\", lit(\"CRITICAL\"))\n)\n\nprint(f\"Structuring alerts: {df_structuring_check.count():,}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-51-financial-fraud-scoring-c14",
    "type": "code",
    "source": "# Combine AML alerts\naml_columns = [\n    \"txn_id\", \"txn_ts\", \"acct_id\", \"card_hash\", \"amount\",\n    \"channel\", \"alert_type\", \"alert_reason\", \"alert_priority\",\n]\n\ndf_aml = df_ctr.select(*aml_columns).union(\n    df_structuring_check.select(*aml_columns)\n).withColumn(\"_alert_generated_at\", current_timestamp())\n\n(\n    df_aml\n    .write\n    .format(\"delta\")\n    .mode(\"overwrite\")\n    .option(\"overwriteSchema\", \"true\")\n    .saveAsTable(GOLD_AML_ALERTS)\n)\n\nprint(f\"Total AML alerts written: {df_aml.count():,}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-51-financial-fraud-scoring-c15",
    "type": "markdown",
    "source": "## Daily Fraud Summary"
  },
  {
    "id": "gold-51-financial-fraud-scoring-c16",
    "type": "code",
    "source": "df_daily = (\n    df_scored\n    .withColumn(\"txn_date\", to_date(\"txn_ts\"))\n    .groupBy(\"txn_date\")\n    .agg(\n        count(\"txn_id\").alias(\"total_txns\"),\n        spark_sum(when(col(\"is_fraud\"), 1).otherwise(0)).alias(\"fraud_count\"),\n        spark_round(\n            spark_sum(when(col(\"is_fraud\"), col(\"amount\")).otherwise(0)), 2\n        ).alias(\"fraud_loss_amount\"),\n        spark_round(avg(\"fraud_score\"), 4).alias(\"avg_fraud_score\"),\n        spark_sum(when(col(\"fraud_decision\") == \"DECLINE\", 1).otherwise(0)).alias(\"declined_count\"),\n        spark_sum(when(col(\"fraud_decision\") == \"STEP_UP_AUTH\", 1).otherwise(0)).alias(\"step_up_count\"),\n        spark_round(spark_sum(\"amount\"), 2).alias(\"total_volume\"),\n    )\n    .withColumn(\n        \"fraud_rate\",\n        spark_round(col(\"fraud_count\") / col(\"total_txns\"), 6),\n    )\n    .withColumn(\"_computed_at\", current_timestamp())\n    .orderBy(\"txn_date\")\n)\n\n(\n    df_daily\n    .write\n    .format(\"delta\")\n    .mode(\"overwrite\")\n    .option(\"overwriteSchema\", \"true\")\n    .saveAsTable(GOLD_DAILY_SUMMARY)\n)\n\nprint(f\"Daily summary written: {df_daily.count()} days\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-51-financial-fraud-scoring-c17",
    "type": "markdown",
    "source": "## Output Summary"
  },
  {
    "id": "gold-51-financial-fraud-scoring-c18",
    "type": "code",
    "source": "print(\"=\" * 60)\nprint(\"GOLD LAYER - FINANCIAL FRAUD SCORING COMPLETE\")\nprint(\"=\" * 60)\n\nfraud_stats = spark.sql(f\"\"\"\n    SELECT\n        COUNT(*) AS total_scored,\n        SUM(CASE WHEN fraud_decision = 'DECLINE' THEN 1 ELSE 0 END) AS declined,\n        SUM(CASE WHEN fraud_decision = 'STEP_UP_AUTH' THEN 1 ELSE 0 END) AS step_up,\n        SUM(CASE WHEN fraud_decision = 'APPROVE' THEN 1 ELSE 0 END) AS approved,\n        ROUND(AVG(fraud_score), 4) AS avg_score,\n        ROUND(AVG(CASE WHEN is_fraud THEN fraud_score END), 4) AS avg_score_fraud,\n        ROUND(AVG(CASE WHEN NOT is_fraud THEN fraud_score END), 4) AS avg_score_legit\n    FROM {GOLD_FRAUD_SCORES}\n\"\"\")\nfraud_stats.show(truncate=False)\n\naml_stats = spark.sql(f\"\"\"\n    SELECT alert_type, alert_priority, COUNT(*) AS alert_count\n    FROM {GOLD_AML_ALERTS}\n    GROUP BY alert_type, alert_priority\n    ORDER BY alert_type\n\"\"\")\naml_stats.show(truncate=False)",
    "lang": "pyspark"
  },
  {
    "id": "gold-51-financial-fraud-scoring-c19",
    "type": "code",
    "source": "from notebookutils import mssparkutils\n\nmssparkutils.notebook.exit(f\"gold_fraud_scoring complete at {datetime.now().isoformat()}\")",
    "lang": "pyspark"
  }
];

const CELLS_GOLD_52_INSURANCE_PREDICTIONS: NotebookCell[] = [
  {
    "id": "gold-52-insurance-predictions-c0",
    "type": "markdown",
    "source": "# Gold Layer: Insurance Claims Analytics & Predictions\n\nComputes actuarial and fraud analytics from validated silver claims:\n\n1. **Loss Ratio** by LOB, state, quarter\n2. **Severity Distribution** by LOB\n3. **Fraud Score Features** for ML scoring\n4. **IBNR Triangle** (incurred-but-not-reported loss development)\n5. **Claims Closure Rate** trending\n6. **Subrogation Recovery Rate**\n\n## Targets\n- `gold_insurance_loss_triangles`\n- `gold_insurance_fraud_scores`\n- `gold_insurance_loss_ratios`\n- `gold_insurance_kpis`"
  },
  {
    "id": "gold-52-insurance-predictions-c1",
    "type": "markdown",
    "source": "## Configuration"
  },
  {
    "id": "gold-52-insurance-predictions-c2",
    "type": "code",
    "source": "from pyspark.sql import SparkSession, Window\nfrom pyspark.sql.functions import (\n    avg,\n    col,\n    count,\n    countDistinct,\n    current_timestamp,\n    lit,\n    log as spark_log,\n    quarter,\n    round as spark_round,\n    stddev,\n    sum as spark_sum,\n    when,\n    year,\n)\n\nspark = SparkSession.builder.getOrCreate()\n\nSILVER_TABLE = \"lh_silver.silver_insurance_claims\"",
    "lang": "pyspark"
  },
  {
    "id": "gold-52-insurance-predictions-c3",
    "type": "markdown",
    "source": "## Read Silver Data"
  },
  {
    "id": "gold-52-insurance-predictions-c4",
    "type": "code",
    "source": "df = spark.table(SILVER_TABLE)\ntotal = df.count()\nprint(f\"Silver records: {total:,}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-52-insurance-predictions-c5",
    "type": "markdown",
    "source": "## 1. Loss Ratio by LOB / State / Quarter"
  },
  {
    "id": "gold-52-insurance-predictions-c6",
    "type": "code",
    "source": "df_loss_ratio = (\n    df\n    .withColumn(\"accident_year\", year(\"loss_dt\"))\n    .withColumn(\"accident_quarter\", quarter(\"loss_dt\"))\n    .groupBy(\"line_of_business\", \"state\", \"accident_year\", \"accident_quarter\")\n    .agg(\n        spark_sum(\"reserve_amt\").alias(\"incurred_losses\"),\n        spark_sum(\"paid_amt\").alias(\"paid_losses\"),\n        count(\"*\").alias(\"claim_count\"),\n        countDistinct(\"policy_id\").alias(\"policy_count\"),\n    )\n)\n\n# Loss ratio requires earned premium; approximate from claim-level data\n# In production, join to policy-level earned premium table\ndf_loss_ratio = df_loss_ratio.withColumn(\n    \"loss_ratio_estimate\",\n    spark_round(col(\"incurred_losses\") / (col(\"policy_count\") * 2500), 4),\n)\n\ndf_loss_ratio = df_loss_ratio.withColumn(\"_computed_at\", current_timestamp())\n\n(\n    df_loss_ratio\n    .write.format(\"delta\")\n    .mode(\"overwrite\")\n    .option(\"overwriteSchema\", \"true\")\n    .saveAsTable(\"lh_gold.gold_insurance_loss_ratios\")\n)\n\nprint(f\"Loss ratios written: {df_loss_ratio.count():,} rows\")\ndf_loss_ratio.show(10, truncate=False)",
    "lang": "pyspark"
  },
  {
    "id": "gold-52-insurance-predictions-c7",
    "type": "markdown",
    "source": "## 2. Severity Distribution by LOB"
  },
  {
    "id": "gold-52-insurance-predictions-c8",
    "type": "code",
    "source": "df_severity = (\n    df\n    .groupBy(\"line_of_business\")\n    .agg(\n        avg(\"reserve_amt\").alias(\"avg_severity\"),\n        stddev(\"reserve_amt\").alias(\"stddev_severity\"),\n        spark_sum(\"reserve_amt\").alias(\"total_incurred\"),\n        count(\"*\").alias(\"claim_count\"),\n        avg(\"paid_amt\").alias(\"avg_paid\"),\n    )\n    .withColumn(\"cv_severity\", spark_round(col(\"stddev_severity\") / col(\"avg_severity\"), 4))\n    .withColumn(\"_computed_at\", current_timestamp())\n)\n\nprint(\"=== Severity Distribution by LOB ===\")\ndf_severity.show(truncate=False)",
    "lang": "pyspark"
  },
  {
    "id": "gold-52-insurance-predictions-c9",
    "type": "markdown",
    "source": "## 3. Fraud Score Features"
  },
  {
    "id": "gold-52-insurance-predictions-c10",
    "type": "code",
    "source": "# Build feature vector per claim for fraud scoring\ndf_fraud = (\n    df\n    .withColumn(\"report_lag_score\", when(col(\"report_lag_days\") > 30, 1.0).otherwise(0.0))\n    .withColumn(\"high_reserve_score\", when(col(\"reserve_amt\") > 50000, 1.0).otherwise(0.0))\n    .withColumn(\"reopened_score\", when(col(\"status\") == \"reopened\", 1.0).otherwise(0.0))\n    .withColumn(\"zero_paid_score\", when(col(\"paid_amt\") == 0, 0.5).otherwise(0.0))\n    .withColumn(\"log_reserve\", spark_log(col(\"reserve_amt\") + 1))\n)\n\n# Aggregate fraud features\ndf_fraud_scores = (\n    df_fraud\n    .withColumn(\n        \"fraud_score\",\n        spark_round(\n            (col(\"report_lag_score\") * 25\n             + col(\"high_reserve_score\") * 30\n             + col(\"reopened_score\") * 20\n             + col(\"zero_paid_score\") * 10\n             + when(col(\"fraud_flag\"), 15.0).otherwise(0.0)),\n            2,\n        ),\n    )\n    .select(\n        \"claim_id\", \"policy_id\", \"line_of_business\", \"state\",\n        \"loss_type\", \"reserve_amt\", \"paid_amt\", \"report_lag_days\",\n        \"fraud_flag\", \"fraud_score\",\n        \"report_lag_score\", \"high_reserve_score\", \"reopened_score\",\n        \"zero_paid_score\", \"log_reserve\",\n    )\n    .withColumn(\"_scored_at\", current_timestamp())\n)\n\n(\n    df_fraud_scores\n    .write.format(\"delta\")\n    .mode(\"overwrite\")\n    .option(\"overwriteSchema\", \"true\")\n    .saveAsTable(\"lh_gold.gold_insurance_fraud_scores\")\n)\n\nfraud_count = df_fraud_scores.filter(col(\"fraud_score\") > 75).count()\nprint(f\"Fraud scores written: {df_fraud_scores.count():,} claims\")\nprint(f\"High-risk referrals (score > 75): {fraud_count:,}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-52-insurance-predictions-c11",
    "type": "markdown",
    "source": "## 4. IBNR Loss Development Triangle"
  },
  {
    "id": "gold-52-insurance-predictions-c12",
    "type": "code",
    "source": "# Build loss triangle: accident quarter x development quarter\ndf_triangle = (\n    df\n    .withColumn(\"accident_year\", year(\"loss_dt\"))\n    .withColumn(\"accident_qtr\", quarter(\"loss_dt\"))\n    .withColumn(\"accident_period\", (col(\"accident_year\") * 10 + col(\"accident_qtr\")))\n    .withColumn(\"dev_quarter\", (col(\"development_age_months\") / 3).cast(\"int\") + 1)\n    .groupBy(\"line_of_business\", \"accident_period\", \"dev_quarter\")\n    .agg(\n        spark_sum(\"reserve_amt\").alias(\"cumulative_incurred\"),\n        spark_sum(\"paid_amt\").alias(\"cumulative_paid\"),\n        count(\"*\").alias(\"claim_count\"),\n    )\n    .orderBy(\"line_of_business\", \"accident_period\", \"dev_quarter\")\n    .withColumn(\"_computed_at\", current_timestamp())\n)\n\n(\n    df_triangle\n    .write.format(\"delta\")\n    .mode(\"overwrite\")\n    .option(\"overwriteSchema\", \"true\")\n    .saveAsTable(\"lh_gold.gold_insurance_loss_triangles\")\n)\n\nprint(f\"Loss triangle rows: {df_triangle.count():,}\")\ndf_triangle.filter(col(\"line_of_business\") == \"auto\").show(20, truncate=False)",
    "lang": "pyspark"
  },
  {
    "id": "gold-52-insurance-predictions-c13",
    "type": "markdown",
    "source": "## 5. Claims Closure Rate & Subrogation Recovery"
  },
  {
    "id": "gold-52-insurance-predictions-c14",
    "type": "code",
    "source": "closed_statuses = [\"closed_paid\", \"closed_no_pay\"]\n\ndf_kpis = (\n    df\n    .withColumn(\"accident_year\", year(\"loss_dt\"))\n    .withColumn(\"accident_qtr\", quarter(\"loss_dt\"))\n    .groupBy(\"line_of_business\", \"accident_year\", \"accident_qtr\")\n    .agg(\n        count(\"*\").alias(\"total_claims\"),\n        spark_sum(when(col(\"status\").isin(closed_statuses), 1).otherwise(0)).alias(\"closed_claims\"),\n        spark_sum(when(col(\"status\") == \"subrogation\", 1).otherwise(0)).alias(\"subro_claims\"),\n        spark_sum(when(col(\"status\") == \"subrogation\", col(\"paid_amt\")).otherwise(0)).alias(\"subro_paid\"),\n        spark_sum(when(col(\"status\") == \"subrogation\", col(\"reserve_amt\")).otherwise(0)).alias(\"subro_reserve\"),\n        avg(\"report_lag_days\").alias(\"avg_report_lag\"),\n        avg(\"reserve_amt\").alias(\"avg_reserve\"),\n    )\n    .withColumn(\"closure_rate\", spark_round(col(\"closed_claims\") / col(\"total_claims\"), 4))\n    .withColumn(\n        \"subro_recovery_rate\",\n        when(col(\"subro_reserve\") > 0,\n             spark_round(col(\"subro_paid\") / col(\"subro_reserve\"), 4))\n        .otherwise(lit(0.0)),\n    )\n    .withColumn(\"_computed_at\", current_timestamp())\n)\n\n(\n    df_kpis\n    .write.format(\"delta\")\n    .mode(\"overwrite\")\n    .option(\"overwriteSchema\", \"true\")\n    .saveAsTable(\"lh_gold.gold_insurance_kpis\")\n)\n\nprint(f\"KPI rows written: {df_kpis.count():,}\")\ndf_kpis.show(10, truncate=False)",
    "lang": "pyspark"
  },
  {
    "id": "gold-52-insurance-predictions-c15",
    "type": "markdown",
    "source": "## Summary"
  },
  {
    "id": "gold-52-insurance-predictions-c16",
    "type": "code",
    "source": "print(\"=== Gold Layer Insurance Analytics Complete ===\")\nprint(f\"  gold_insurance_loss_ratios:    {df_loss_ratio.count():,} rows\")\nprint(f\"  gold_insurance_fraud_scores:   {df_fraud_scores.count():,} rows\")\nprint(f\"  gold_insurance_loss_triangles: {df_triangle.count():,} rows\")\nprint(f\"  gold_insurance_kpis:           {df_kpis.count():,} rows\")\nprint()\nprint(\"Downstream: Power BI Direct Lake dashboards, SIU referral queue, statutory feeds\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-52-insurance-predictions-c17",
    "type": "markdown",
    "source": "## Notebook Complete\n\nGold analytics for insurance claims are ready.\nConnect Power BI via Direct Lake for real-time dashboards."
  }
];

const CELLS_GOLD_53_RETAIL_DEMAND_FORECAST: NotebookCell[] = [
  {
    "id": "gold-53-retail-demand-forecast-c0",
    "type": "markdown",
    "source": "# Gold Layer: Retail Demand Forecast & Customer 360\n\nAggregate daily sales for demand forecasting features and build\ncustomer-level RFM scores / CLV estimates.\n\n## Outputs\n- **gold_retail_demand** — SKU × Store × Day with forecast features\n- **gold_retail_customer_360** — RFM, CLV, segment per customer\n\n## Source\n- **silver_retail_sales**"
  },
  {
    "id": "gold-53-retail-demand-forecast-c1",
    "type": "markdown",
    "source": "## Configuration"
  },
  {
    "id": "gold-53-retail-demand-forecast-c2",
    "type": "code",
    "source": "from pyspark.sql import SparkSession\nfrom pyspark.sql.functions import (\n    avg,\n    col,\n    count,\n    countDistinct,\n    current_date,\n    current_timestamp,\n    datediff,\n    dayofweek,\n    lit,\n    max as spark_max,\n    min as spark_min,\n    month,\n    ntile,\n    round as spark_round,\n    sum as spark_sum,\n    weekofyear,\n    when,\n)\nfrom pyspark.sql.window import Window\n\nSOURCE_TABLE = \"lh_silver.silver_retail_sales\"\nDEMAND_TABLE = \"lh_gold.gold_retail_demand\"\nCUSTOMER_TABLE = \"lh_gold.gold_retail_customer_360\"\n\nprint(f\"Source: {SOURCE_TABLE}\")\nprint(f\"Demand target: {DEMAND_TABLE}\")\nprint(f\"Customer target: {CUSTOMER_TABLE}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-53-retail-demand-forecast-c3",
    "type": "markdown",
    "source": "## Read Silver Sales"
  },
  {
    "id": "gold-53-retail-demand-forecast-c4",
    "type": "code",
    "source": "df_sales = spark.table(SOURCE_TABLE).filter(~col(\"is_return\"))\ntotal_sales = df_sales.count()\nprint(f\"Sales records (excl. returns): {total_sales:,}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-53-retail-demand-forecast-c5",
    "type": "markdown",
    "source": "---\n## Part 1: Demand Forecast Features\n\nAggregate to SKU × Store × Day and compute lag/rolling features."
  },
  {
    "id": "gold-53-retail-demand-forecast-c6",
    "type": "code",
    "source": "# Daily aggregation\ndf_daily = (\n    df_sales\n    .groupBy(\"sku\", \"store_id\", \"txn_date\", \"category\", \"subcategory\", \"region\", \"store_format\")\n    .agg(\n        spark_sum(\"qty\").alias(\"daily_qty\"),\n        spark_sum(\"line_total\").alias(\"daily_revenue\"),\n        count(\"txn_id\").alias(\"txn_count\"),\n        avg(\"discount_pct\").alias(\"avg_discount_pct\"),\n    )\n)\n\ndaily_count = df_daily.count()\nprint(f\"Daily SKU-Store aggregations: {daily_count:,}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-53-retail-demand-forecast-c7",
    "type": "markdown",
    "source": "### Rolling Window Features"
  },
  {
    "id": "gold-53-retail-demand-forecast-c8",
    "type": "code",
    "source": "# Define windows\nw7 = Window.partitionBy(\"sku\", \"store_id\").orderBy(\"txn_date\").rowsBetween(-6, 0)\nw14 = Window.partitionBy(\"sku\", \"store_id\").orderBy(\"txn_date\").rowsBetween(-13, 0)\nw28 = Window.partitionBy(\"sku\", \"store_id\").orderBy(\"txn_date\").rowsBetween(-27, 0)\n\ndf_features = (\n    df_daily\n    # Moving averages\n    .withColumn(\"sales_ma_7d\", spark_round(avg(\"daily_qty\").over(w7), 2))\n    .withColumn(\"sales_ma_14d\", spark_round(avg(\"daily_qty\").over(w14), 2))\n    .withColumn(\"sales_ma_28d\", spark_round(avg(\"daily_qty\").over(w28), 2))\n    # Revenue moving averages\n    .withColumn(\"revenue_ma_7d\", spark_round(avg(\"daily_revenue\").over(w7), 2))\n    # Calendar features\n    .withColumn(\"day_of_week\", dayofweek(\"txn_date\"))\n    .withColumn(\"week_of_year\", weekofyear(\"txn_date\"))\n    .withColumn(\"month_num\", month(\"txn_date\"))\n    # Seasonal index: ratio of current to 28-day average\n    .withColumn(\n        \"seasonal_index\",\n        when(\n            col(\"sales_ma_28d\") > 0,\n            spark_round(col(\"daily_qty\") / col(\"sales_ma_28d\"), 4),\n        ).otherwise(lit(1.0)),\n    )\n    .withColumn(\"_gold_processed_at\", current_timestamp())\n)\n\nprint(f\"Feature columns: {len(df_features.columns)}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-53-retail-demand-forecast-c9",
    "type": "markdown",
    "source": "### Write gold_retail_demand"
  },
  {
    "id": "gold-53-retail-demand-forecast-c10",
    "type": "code",
    "source": "df_features.write \\\n    .format(\"delta\") \\\n    .mode(\"overwrite\") \\\n    .option(\"overwriteSchema\", \"true\") \\\n    .saveAsTable(DEMAND_TABLE)\n\ndemand_count = spark.table(DEMAND_TABLE).count()\nprint(f\"gold_retail_demand rows: {demand_count:,}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-53-retail-demand-forecast-c11",
    "type": "markdown",
    "source": "---\n## Part 2: Customer 360 — RFM & CLV"
  },
  {
    "id": "gold-53-retail-demand-forecast-c12",
    "type": "markdown",
    "source": "### RFM Scoring"
  },
  {
    "id": "gold-53-retail-demand-forecast-c13",
    "type": "code",
    "source": "df_rfm_raw = (\n    df_sales\n    .filter(col(\"loyalty_id\").isNotNull())\n    .groupBy(\"loyalty_id\", \"customer_segment\")\n    .agg(\n        datediff(current_date(), spark_max(\"txn_date\")).alias(\"recency_days\"),\n        countDistinct(\"txn_id\").alias(\"frequency\"),\n        spark_round(spark_sum(\"line_total\"), 2).alias(\"monetary\"),\n        spark_min(\"txn_date\").alias(\"first_purchase_date\"),\n        spark_max(\"txn_date\").alias(\"last_purchase_date\"),\n        countDistinct(\"category\").alias(\"categories_shopped\"),\n        countDistinct(\"store_id\").alias(\"stores_visited\"),\n        avg(\"discount_pct\").alias(\"avg_discount_sensitivity\"),\n    )\n)\n\nrfm_count = df_rfm_raw.count()\nprint(f\"Unique loyalty customers: {rfm_count:,}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-53-retail-demand-forecast-c14",
    "type": "code",
    "source": "# Score each dimension 1-5 using quintiles\n# Recency: lower is better → reverse scoring\nw_r = Window.orderBy(col(\"recency_days\").desc())\nw_f = Window.orderBy(\"frequency\")\nw_m = Window.orderBy(\"monetary\")\n\ndf_rfm = (\n    df_rfm_raw\n    .withColumn(\"r_score\", ntile(5).over(w_r))\n    .withColumn(\"f_score\", ntile(5).over(w_f))\n    .withColumn(\"m_score\", ntile(5).over(w_m))\n    .withColumn(\n        \"rfm_segment\",\n        when((col(\"r_score\") >= 4) & (col(\"f_score\") >= 4) & (col(\"m_score\") >= 4), \"Champions\")\n        .when((col(\"r_score\") >= 3) & (col(\"f_score\") >= 3), \"Loyal\")\n        .when((col(\"r_score\") >= 4) & (col(\"f_score\") <= 2), \"New Customers\")\n        .when((col(\"r_score\") <= 2) & (col(\"f_score\") >= 3), \"At Risk\")\n        .when((col(\"r_score\") <= 2) & (col(\"f_score\") <= 2), \"Hibernating\")\n        .otherwise(\"Potential Loyalists\"),\n    )\n)",
    "lang": "pyspark"
  },
  {
    "id": "gold-53-retail-demand-forecast-c15",
    "type": "markdown",
    "source": "### CLV Estimation\n\nSimple heuristic CLV: avg order value × purchase frequency × expected tenure."
  },
  {
    "id": "gold-53-retail-demand-forecast-c16",
    "type": "code",
    "source": "df_clv = (\n    df_rfm\n    .withColumn(\n        \"avg_order_value\",\n        when(col(\"frequency\") > 0, col(\"monetary\") / col(\"frequency\")).otherwise(0),\n    )\n    .withColumn(\n        \"tenure_months\",\n        spark_round(\n            datediff(col(\"last_purchase_date\"), col(\"first_purchase_date\")) / 30.44, 1\n        ),\n    )\n    .withColumn(\n        \"monthly_frequency\",\n        when(\n            col(\"tenure_months\") > 0,\n            spark_round(col(\"frequency\") / col(\"tenure_months\"), 2),\n        ).otherwise(col(\"frequency\")),\n    )\n    .withColumn(\n        \"clv_12m\",\n        spark_round(col(\"avg_order_value\") * col(\"monthly_frequency\") * 12, 2),\n    )\n    .withColumn(\n        \"clv_tier\",\n        when(col(\"clv_12m\") >= 5000, \"Platinum\")\n        .when(col(\"clv_12m\") >= 2000, \"Gold\")\n        .when(col(\"clv_12m\") >= 500, \"Silver\")\n        .otherwise(\"Bronze\"),\n    )\n    .withColumn(\"_gold_processed_at\", current_timestamp())\n)",
    "lang": "pyspark"
  },
  {
    "id": "gold-53-retail-demand-forecast-c17",
    "type": "markdown",
    "source": "### Write gold_retail_customer_360"
  },
  {
    "id": "gold-53-retail-demand-forecast-c18",
    "type": "code",
    "source": "df_clv.write \\\n    .format(\"delta\") \\\n    .mode(\"overwrite\") \\\n    .option(\"overwriteSchema\", \"true\") \\\n    .saveAsTable(CUSTOMER_TABLE)\n\ncust_count = spark.table(CUSTOMER_TABLE).count()\nprint(f\"gold_retail_customer_360 rows: {cust_count:,}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-53-retail-demand-forecast-c19",
    "type": "markdown",
    "source": "## Summary Statistics"
  },
  {
    "id": "gold-53-retail-demand-forecast-c20",
    "type": "code",
    "source": "display(\n    spark.sql(f\"\"\"\n        SELECT\n            rfm_segment,\n            clv_tier,\n            COUNT(*) AS customers,\n            ROUND(AVG(monetary), 2) AS avg_monetary,\n            ROUND(AVG(clv_12m), 2) AS avg_clv_12m,\n            ROUND(AVG(recency_days), 0) AS avg_recency_days\n        FROM {CUSTOMER_TABLE}\n        GROUP BY rfm_segment, clv_tier\n        ORDER BY avg_clv_12m DESC\n    \"\"\")\n)",
    "lang": "pyspark"
  },
  {
    "id": "gold-53-retail-demand-forecast-c21",
    "type": "code",
    "source": "display(\n    spark.sql(f\"\"\"\n        SELECT\n            category,\n            region,\n            COUNT(*) AS day_records,\n            ROUND(AVG(daily_qty), 1) AS avg_daily_qty,\n            ROUND(AVG(seasonal_index), 3) AS avg_seasonal_idx\n        FROM {DEMAND_TABLE}\n        GROUP BY category, region\n        ORDER BY avg_daily_qty DESC\n        LIMIT 20\n    \"\"\")\n)",
    "lang": "pyspark"
  },
  {
    "id": "gold-53-retail-demand-forecast-c22",
    "type": "code",
    "source": "# Checkpoint\ncheckpoint_path = \"abfss://retail@{{ADLS_ACCOUNT}}.dfs.core.windows.net/checkpoints/gold\"\nmssparkutils.fs.put(\n    f\"{checkpoint_path}/last_run.txt\",\n    f\"demand={demand_count}|customer360={cust_count}\",\n    True,\n)\nprint(\"Gold checkpoint written\")",
    "lang": "pyspark"
  }
];

const CELLS_GOLD_54_MANUFACTURING_OEE: NotebookCell[] = [
  {
    "id": "gold-54-manufacturing-oee-c0",
    "type": "markdown",
    "source": "# Gold Layer: Manufacturing OEE & Maintenance Predictions\n\nComputes Overall Equipment Effectiveness (OEE) per machine per shift and\ngenerates predictive maintenance scores.\n\n## OEE = Availability x Performance x Quality\n\n## Source\n- **Table:** silver_manufacturing_health\n\n## Targets\n- **gold_manufacturing_oee** -- OEE metrics per machine per shift\n- **gold_maintenance_predictions** -- Predictive maintenance scores per machine"
  },
  {
    "id": "gold-54-manufacturing-oee-c1",
    "type": "markdown",
    "source": "## Configuration"
  },
  {
    "id": "gold-54-manufacturing-oee-c2",
    "type": "code",
    "source": "from pyspark.sql import SparkSession, Window\nfrom pyspark.sql.functions import (\n    avg,\n    col,\n    count,\n    current_timestamp,\n    date_trunc,\n    expr,\n    greatest,\n    hour,\n    least,\n    lit,\n    max as spark_max,\n    min as spark_min,\n    sum as spark_sum,\n    when,\n)\n\nSOURCE_TABLE = \"lh_silver.silver_manufacturing_health\"\nOEE_TABLE = \"lh_gold.gold_manufacturing_oee\"\nPREDICTIONS_TABLE = \"lh_gold.gold_maintenance_predictions\"\n\n# Shift definitions (8-hour shifts)\nSHIFT_HOURS = 8\nPLANNED_MINUTES_PER_SHIFT = SHIFT_HOURS * 60  # 480\n\n# Ideal cycle times per machine type (seconds per part)\nIDEAL_CYCLE = {\"CNC\": 120, \"press\": 45, \"robot\": 30, \"conveyor\": 15}\n\nprint(f\"Source: {SOURCE_TABLE}\")\nprint(f\"OEE Target: {OEE_TABLE}\")\nprint(f\"Predictions Target: {PREDICTIONS_TABLE}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-54-manufacturing-oee-c3",
    "type": "markdown",
    "source": "## Read Silver Data"
  },
  {
    "id": "gold-54-manufacturing-oee-c4",
    "type": "code",
    "source": "df_silver = spark.table(SOURCE_TABLE)\nprint(f\"Silver records: {df_silver.count():,}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-54-manufacturing-oee-c5",
    "type": "markdown",
    "source": "## Assign Shifts\n\nShifts: Day (06:00-14:00), Swing (14:00-22:00), Night (22:00-06:00)."
  },
  {
    "id": "gold-54-manufacturing-oee-c6",
    "type": "code",
    "source": "df_shifted = df_silver.withColumn(\n    \"shift\",\n    when((hour(\"window_start\") >= 6) & (hour(\"window_start\") < 14), lit(\"Day\"))\n    .when((hour(\"window_start\") >= 14) & (hour(\"window_start\") < 22), lit(\"Swing\"))\n    .otherwise(lit(\"Night\")),\n).withColumn(\"shift_date\", date_trunc(\"day\", col(\"window_start\")).cast(\"date\"))",
    "lang": "pyspark"
  },
  {
    "id": "gold-54-manufacturing-oee-c7",
    "type": "markdown",
    "source": "## OEE Calculation\n\n### Availability\nFraction of shift minutes where machine was running (non-anomaly).\n\n### Performance\nSimulated from RPM consistency -- ratio of actual throughput to ideal.\n\n### Quality\nSimulated from anomaly and vibration/temperature variance."
  },
  {
    "id": "gold-54-manufacturing-oee-c8",
    "type": "code",
    "source": "df_oee_raw = (\n    df_shifted\n    .groupBy(\"machine_id\", \"machine_type\", \"shift_date\", \"shift\")\n    .agg(\n        count(\"*\").alias(\"total_minutes\"),\n        spark_sum(when(~col(\"is_anomaly\"), 1).otherwise(0)).alias(\"run_minutes\"),\n        avg(\"vibration_avg\").alias(\"avg_vibration\"),\n        avg(\"temperature_avg\").alias(\"avg_temperature\"),\n        avg(\"current_avg\").alias(\"avg_current\"),\n        spark_max(\"vibration_max\").alias(\"peak_vibration\"),\n        spark_max(\"temperature_max\").alias(\"peak_temperature\"),\n        avg(\"rpm_avg\").alias(\"avg_rpm\"),\n        avg(\"vibration_stddev\").alias(\"avg_vib_stddev\"),\n        avg(\"days_since_maintenance\").alias(\"days_since_maint\"),\n        spark_sum(when(col(\"is_anomaly\"), 1).otherwise(0)).alias(\"anomaly_minutes\"),\n    )\n)\n\n# Availability = run_minutes / planned_minutes\ndf_oee = df_oee_raw.withColumn(\n    \"availability\",\n    least(lit(1.0), col(\"run_minutes\") / lit(PLANNED_MINUTES_PER_SHIFT)),\n)\n\n# Performance: simulate based on RPM stability\n# Higher RPM stddev => lower performance\ndf_oee = df_oee.withColumn(\n    \"performance\",\n    least(\n        lit(1.0),\n        greatest(\n            lit(0.3),\n            lit(0.95) - (col(\"avg_vib_stddev\") * 0.05),\n        ),\n    ),\n)\n\n# Quality: simulate from anomaly rate\ndf_oee = df_oee.withColumn(\n    \"quality\",\n    least(\n        lit(1.0),\n        greatest(\n            lit(0.5),\n            lit(1.0) - (col(\"anomaly_minutes\") / greatest(col(\"total_minutes\"), lit(1))) * 2,\n        ),\n    ),\n)\n\n# OEE composite\ndf_oee = df_oee.withColumn(\n    \"oee\", col(\"availability\") * col(\"performance\") * col(\"quality\")\n)\n\n# Energy per unit (simulated: current_avg * voltage_assumed / parts_estimated)\nASSUMED_VOLTAGE = 480  # 3-phase industrial\ndf_oee = df_oee.withColumn(\n    \"energy_kwh_per_unit\",\n    (col(\"avg_current\") * lit(ASSUMED_VOLTAGE) * col(\"run_minutes\") / 60 / 1000)\n    / greatest(col(\"run_minutes\") * lit(0.5), lit(1)),  # ~0.5 parts/min estimate\n)\n\n# Add processing timestamp\ndf_oee = df_oee.withColumn(\"_gold_processed_at\", current_timestamp())\n\nprint(f\"OEE records: {df_oee.count():,}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-54-manufacturing-oee-c9",
    "type": "markdown",
    "source": "## Write OEE Table"
  },
  {
    "id": "gold-54-manufacturing-oee-c10",
    "type": "code",
    "source": "df_oee.write \\\n    .format(\"delta\") \\\n    .mode(\"overwrite\") \\\n    .option(\"overwriteSchema\", \"true\") \\\n    .saveAsTable(OEE_TABLE)\n\nprint(f\"Written to {OEE_TABLE}: {spark.table(OEE_TABLE).count():,} rows\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-54-manufacturing-oee-c11",
    "type": "markdown",
    "source": "## Predictive Maintenance Scoring\n\nComposite score (0-100) based on:\n- Vibration trend (weight 0.35)\n- Temperature trend (weight 0.25)\n- Current trend (weight 0.20)\n- Days since maintenance (weight 0.20)"
  },
  {
    "id": "gold-54-manufacturing-oee-c12",
    "type": "code",
    "source": "# Latest shift per machine for prediction\nw_latest = Window.partitionBy(\"machine_id\").orderBy(col(\"shift_date\").desc(), col(\"shift\").desc())\n\ndf_latest = (\n    df_oee\n    .withColumn(\"rn\", expr(\"row_number() over (partition by machine_id order by shift_date desc, shift desc)\"))\n    .filter(col(\"rn\") == 1)\n    .drop(\"rn\")\n)\n\n# Normalize components to 0-100\ndf_pred = (\n    df_latest\n    .withColumn(\n        \"vibration_score\",\n        least(lit(100), (col(\"peak_vibration\") / lit(7.0)) * 100),\n    )\n    .withColumn(\n        \"temperature_score\",\n        least(lit(100), (col(\"peak_temperature\") / lit(85.0)) * 100),\n    )\n    .withColumn(\n        \"current_score\",\n        least(lit(100), (col(\"avg_current\") / lit(55.0)) * 100),\n    )\n    .withColumn(\n        \"maintenance_age_score\",\n        least(lit(100), (col(\"days_since_maint\") / lit(90.0)) * 100),\n    )\n    .withColumn(\n        \"maintenance_risk_score\",\n        (col(\"vibration_score\") * 0.35)\n        + (col(\"temperature_score\") * 0.25)\n        + (col(\"current_score\") * 0.20)\n        + (col(\"maintenance_age_score\") * 0.20),\n    )\n    .withColumn(\n        \"recommended_action\",\n        when(col(\"maintenance_risk_score\") > 80, lit(\"IMMEDIATE - Schedule maintenance within 24h\"))\n        .when(col(\"maintenance_risk_score\") > 60, lit(\"SOON - Schedule maintenance within 7 days\"))\n        .when(col(\"maintenance_risk_score\") > 40, lit(\"MONITOR - Increase inspection frequency\"))\n        .otherwise(lit(\"NORMAL - Continue standard schedule\")),\n    )\n    .select(\n        \"machine_id\",\n        \"machine_type\",\n        \"shift_date\",\n        \"avg_vibration\",\n        \"peak_vibration\",\n        \"avg_temperature\",\n        \"peak_temperature\",\n        \"avg_current\",\n        \"days_since_maint\",\n        \"oee\",\n        \"vibration_score\",\n        \"temperature_score\",\n        \"current_score\",\n        \"maintenance_age_score\",\n        \"maintenance_risk_score\",\n        \"recommended_action\",\n    )\n    .withColumn(\"_gold_processed_at\", current_timestamp())\n)\n\nprint(f\"Prediction records: {df_pred.count():,}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-54-manufacturing-oee-c13",
    "type": "markdown",
    "source": "## Write Predictions Table"
  },
  {
    "id": "gold-54-manufacturing-oee-c14",
    "type": "code",
    "source": "df_pred.write \\\n    .format(\"delta\") \\\n    .mode(\"overwrite\") \\\n    .option(\"overwriteSchema\", \"true\") \\\n    .saveAsTable(PREDICTIONS_TABLE)\n\nprint(f\"Written to {PREDICTIONS_TABLE}: {spark.table(PREDICTIONS_TABLE).count():,} rows\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-54-manufacturing-oee-c15",
    "type": "markdown",
    "source": "## Verification"
  },
  {
    "id": "gold-54-manufacturing-oee-c16",
    "type": "code",
    "source": "print(\"=== OEE Summary by Machine Type ===\")\ndisplay(\n    spark.table(OEE_TABLE)\n    .groupBy(\"machine_type\")\n    .agg(\n        avg(\"oee\").alias(\"avg_oee\"),\n        avg(\"availability\").alias(\"avg_availability\"),\n        avg(\"performance\").alias(\"avg_performance\"),\n        avg(\"quality\").alias(\"avg_quality\"),\n        avg(\"energy_kwh_per_unit\").alias(\"avg_energy_per_unit\"),\n    )\n)",
    "lang": "pyspark"
  },
  {
    "id": "gold-54-manufacturing-oee-c17",
    "type": "code",
    "source": "print(\"=== Maintenance Risk Distribution ===\")\ndisplay(\n    spark.table(PREDICTIONS_TABLE)\n    .groupBy(\"recommended_action\")\n    .agg(count(\"*\").alias(\"machine_count\"))\n    .orderBy(\"machine_count\")\n)",
    "lang": "pyspark"
  },
  {
    "id": "gold-54-manufacturing-oee-c18",
    "type": "code",
    "source": "print(\"=== Top 10 Highest Risk Machines ===\")\ndisplay(\n    spark.table(PREDICTIONS_TABLE)\n    .orderBy(col(\"maintenance_risk_score\").desc())\n    .select(\n        \"machine_id\", \"machine_type\", \"maintenance_risk_score\",\n        \"oee\", \"recommended_action\"\n    )\n    .limit(10)\n)",
    "lang": "pyspark"
  },
  {
    "id": "gold-54-manufacturing-oee-c19",
    "type": "markdown",
    "source": "## Summary\n\n| Table | Purpose | Rows |\n|-------|---------|------|\n| gold_manufacturing_oee | OEE per machine per shift | Per machine x shift |\n| gold_maintenance_predictions | Risk scores + recommendations | Per machine (latest) |\n\n**Next Step:** Power BI Direct Lake dashboard for OEE real-time monitoring."
  }
];

const CELLS_GOLD_55_ENERGY_GRID_KPIS: NotebookCell[] = [
  {
    "id": "gold-55-energy-grid-kpis-c0",
    "type": "markdown",
    "source": "# Gold Layer: Energy Grid KPIs\n\nThis notebook computes grid reliability indices, load forecasting features,\nand revenue protection scores from Silver-layer energy data.\n\n## Outputs\n- **gold_grid_reliability**: SAIDI/SAIFI/CAIDI by feeder and district (IEEE 1366)\n- **gold_energy_forecasts**: Peak demand, load factor, DR eligibility\n- **gold_revenue_protection**: Theft detection scores and estimated losses\n\n## Compliance\n- NERC CIP audit trail\n- IEEE 1366 Major Event Day exclusion"
  },
  {
    "id": "gold-55-energy-grid-kpis-c1",
    "type": "markdown",
    "source": "## Configuration"
  },
  {
    "id": "gold-55-energy-grid-kpis-c2",
    "type": "code",
    "source": "from datetime import datetime\n\nfrom pyspark.sql.functions import (\n    avg,\n    col,\n    count,\n    countDistinct,\n    current_timestamp,\n    expr,\n    lit,\n    max as spark_max,\n    min as spark_min,\n    round as spark_round,\n    sum as spark_sum,\n    to_date,\n    when,\n)\n\nSILVER_CONSUMPTION = \"lh_silver.silver_energy_consumption\"\nBRONZE_OUTAGES = \"lh_bronze.bronze_energy_outage_events\"\nGOLD_RELIABILITY = \"lh_gold.gold_grid_reliability\"\nGOLD_FORECASTS = \"lh_gold.gold_energy_forecasts\"\nGOLD_REVENUE = \"lh_gold.gold_revenue_protection\"\nBATCH_ID = datetime.now().strftime(\"%Y%m%d_%H%M%S\")\n\n# System-wide customer count for SAIDI/SAIFI\nTOTAL_CUSTOMERS = 1_200_000\n\nprint(f\"Batch: {BATCH_ID}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-55-energy-grid-kpis-c3",
    "type": "markdown",
    "source": "## Grid Reliability Indices (IEEE 1366)\n\n- **SAIDI** = Sum(Customer Minutes Interrupted) / Total Customers\n- **SAIFI** = Sum(Customers Interrupted) / Total Customers\n- **CAIDI** = SAIDI / SAIFI"
  },
  {
    "id": "gold-55-energy-grid-kpis-c4",
    "type": "code",
    "source": "df_outages = spark.table(BRONZE_OUTAGES)\n\n# Calculate Customer Minutes Interrupted (CMI)\ndf_cmi = df_outages \\\n    .withColumn(\"cmi\", col(\"duration_minutes\") * col(\"customers_affected\")) \\\n    .withColumn(\"outage_date\", to_date(\"start_datetime\"))\n\n# Daily reliability by district\ndf_daily_reliability = df_cmi \\\n    .filter(col(\"major_event\") == False) \\\n    .groupBy(\"outage_date\", \"district\") \\\n    .agg(\n        spark_sum(\"cmi\").alias(\"total_cmi\"),\n        spark_sum(\"customers_affected\").alias(\"total_customers_interrupted\"),\n        count(\"event_id\").alias(\"outage_count\"),\n        avg(\"duration_minutes\").alias(\"avg_duration_min\"),\n    )\n\n# Compute indices\ndf_reliability = df_daily_reliability \\\n    .withColumn(\"saidi\", spark_round(col(\"total_cmi\") / lit(TOTAL_CUSTOMERS / 5), 4)) \\\n    .withColumn(\"saifi\", spark_round(col(\"total_customers_interrupted\") / lit(TOTAL_CUSTOMERS / 5), 6)) \\\n    .withColumn(\n        \"caidi\",\n        spark_round(\n            when(col(\"saifi\") > 0, col(\"saidi\") / col(\"saifi\")).otherwise(0.0),\n            2\n        )\n    ) \\\n    .withColumn(\n        \"asai\",\n        spark_round(\n            lit(1.0) - (col(\"saidi\") / lit(1440.0)),  # 1440 min/day\n            6\n        )\n    ) \\\n    .withColumn(\"period\", lit(\"daily\")) \\\n    .withColumn(\"period_start\", col(\"outage_date\")) \\\n    .withColumn(\"customers_served\", lit(TOTAL_CUSTOMERS // 5)) \\\n    .withColumn(\"excluding_med\", lit(True)) \\\n    .select(\n        \"period\", \"period_start\", \"district\",\n        \"saidi\", \"saifi\", \"caidi\", \"asai\",\n        \"customers_served\", \"total_cmi\", \"outage_count\", \"excluding_med\",\n    )",
    "lang": "pyspark"
  },
  {
    "id": "gold-55-energy-grid-kpis-c5",
    "type": "markdown",
    "source": "## Feeder-Level Reliability"
  },
  {
    "id": "gold-55-energy-grid-kpis-c6",
    "type": "code",
    "source": "df_feeder_reliability = df_cmi \\\n    .filter(col(\"major_event\") == False) \\\n    .groupBy(\"outage_date\", \"district\", \"feeder_id\") \\\n    .agg(\n        spark_sum(\"cmi\").alias(\"total_cmi\"),\n        spark_sum(\"customers_affected\").alias(\"total_customers_interrupted\"),\n        count(\"event_id\").alias(\"outage_count\"),\n    ) \\\n    .withColumn(\"saidi\", spark_round(col(\"total_cmi\") / lit(5000), 4)) \\\n    .withColumn(\"saifi\", spark_round(col(\"total_customers_interrupted\") / lit(5000), 6)) \\\n    .withColumn(\n        \"caidi\",\n        spark_round(\n            when(col(\"saifi\") > 0, col(\"saidi\") / col(\"saifi\")).otherwise(0.0), 2\n        )\n    ) \\\n    .withColumn(\"asai\", spark_round(lit(1.0) - (col(\"saidi\") / lit(1440.0)), 6)) \\\n    .withColumn(\"period\", lit(\"daily\")) \\\n    .withColumn(\"period_start\", col(\"outage_date\")) \\\n    .withColumn(\"customers_served\", lit(5000)) \\\n    .withColumn(\"excluding_med\", lit(True)) \\\n    .select(\n        \"period\", \"period_start\", \"district\", \"feeder_id\",\n        \"saidi\", \"saifi\", \"caidi\", \"asai\",\n        \"customers_served\", \"total_cmi\", \"outage_count\", \"excluding_med\",\n    )\n\n# Union district + feeder level\ndf_all_reliability = df_reliability \\\n    .withColumn(\"feeder_id\", lit(None).cast(\"string\")) \\\n    .unionByName(df_feeder_reliability)",
    "lang": "pyspark"
  },
  {
    "id": "gold-55-energy-grid-kpis-c7",
    "type": "markdown",
    "source": "## Write Grid Reliability"
  },
  {
    "id": "gold-55-energy-grid-kpis-c8",
    "type": "code",
    "source": "df_all_reliability.write \\\n    .format(\"delta\") \\\n    .mode(\"overwrite\") \\\n    .option(\"overwriteSchema\", \"true\") \\\n    .saveAsTable(GOLD_RELIABILITY)\n\nrel_count = spark.table(GOLD_RELIABILITY).count()\nprint(f\"Grid reliability records: {rel_count:,}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-55-energy-grid-kpis-c9",
    "type": "markdown",
    "source": "## Load Forecasting Features"
  },
  {
    "id": "gold-55-energy-grid-kpis-c10",
    "type": "code",
    "source": "df_silver = spark.table(SILVER_CONSUMPTION)\n\n# Peak demand and load factor by district and date\ndf_load = df_silver \\\n    .withColumn(\"reading_date\", to_date(\"reading_timestamp\")) \\\n    .groupBy(\"reading_date\", \"district\") \\\n    .agg(\n        spark_max(\"demand_kw\").alias(\"peak_demand_kw\"),\n        avg(\"demand_kw\").alias(\"avg_demand_kw\"),\n        spark_sum(\"kwh_delivered\").alias(\"total_kwh\"),\n        countDistinct(\"meter_id\").alias(\"active_meters\"),\n    ) \\\n    .withColumn(\n        \"load_factor\",\n        spark_round(\n            when(col(\"peak_demand_kw\") > 0,\n                 col(\"avg_demand_kw\") / col(\"peak_demand_kw\"))\n            .otherwise(0.0), 4\n        )\n    ) \\\n    .withColumn(\"peak_demand_mw\", spark_round(col(\"peak_demand_kw\") / 1000.0, 2)) \\\n    .withColumn(\n        \"dr_eligible_mw\",\n        spark_round(col(\"peak_demand_mw\") * 0.08, 2)  # ~8% DR eligible\n    ) \\\n    .withColumn(\n        \"peak_flag\",\n        when(col(\"peak_demand_mw\") > lit(2500), True).otherwise(False)\n    )",
    "lang": "pyspark"
  },
  {
    "id": "gold-55-energy-grid-kpis-c11",
    "type": "markdown",
    "source": "## Write Load Forecasts"
  },
  {
    "id": "gold-55-energy-grid-kpis-c12",
    "type": "code",
    "source": "df_forecasts = df_load.select(\n    col(\"reading_date\").alias(\"forecast_date\"),\n    col(\"district\"),\n    col(\"peak_demand_mw\").alias(\"predicted_mw\"),\n    col(\"load_factor\"),\n    col(\"total_kwh\"),\n    col(\"active_meters\"),\n    col(\"dr_eligible_mw\"),\n    col(\"peak_flag\"),\n    current_timestamp().alias(\"_gold_processed_at\"),\n    lit(BATCH_ID).alias(\"_gold_batch_id\"),\n)\n\ndf_forecasts.write \\\n    .format(\"delta\") \\\n    .mode(\"overwrite\") \\\n    .option(\"overwriteSchema\", \"true\") \\\n    .saveAsTable(GOLD_FORECASTS)\n\nforecast_count = spark.table(GOLD_FORECASTS).count()\nprint(f\"Forecast records: {forecast_count:,}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-55-energy-grid-kpis-c13",
    "type": "markdown",
    "source": "## Revenue Protection (Theft Detection)"
  },
  {
    "id": "gold-55-energy-grid-kpis-c14",
    "type": "code",
    "source": "# Aggregate tamper scores by meter\ndf_theft = df_silver \\\n    .withColumn(\"analysis_date\", to_date(\"reading_timestamp\")) \\\n    .groupBy(\"meter_id\", \"analysis_date\", \"district\", \"rate_class\") \\\n    .agg(\n        avg(\"tamper_score\").alias(\"avg_tamper_score\"),\n        spark_max(\"tamper_score\").alias(\"max_tamper_score\"),\n        spark_sum(\"kwh_delivered\").alias(\"daily_kwh\"),\n        count(\"*\").alias(\"reading_count\"),\n    ) \\\n    .withColumn(\n        \"theft_score\",\n        spark_round(\n            col(\"avg_tamper_score\") * 0.4 +\n            col(\"max_tamper_score\") * 0.4 +\n            when(col(\"reading_count\") < 80, 0.2).otherwise(0.0),  # missing reads\n            4\n        )\n    ) \\\n    .withColumn(\n        \"anomaly_type\",\n        when(col(\"max_tamper_score\") > 0.7, lit(\"METER_TAMPER\"))\n        .when(col(\"reading_count\") < 50, lit(\"MISSING_READS\"))\n        .when(col(\"daily_kwh\") < 0.5, lit(\"ZERO_CONSUMPTION\"))\n        .otherwise(lit(\"NONE\"))\n    ) \\\n    .withColumn(\n        \"estimated_loss_kwh\",\n        when(col(\"theft_score\") > 0.3,\n             spark_round(col(\"daily_kwh\") * col(\"theft_score\") * 2.0, 2))\n        .otherwise(0.0)\n    ) \\\n    .withColumn(\n        \"estimated_loss_usd\",\n        spark_round(col(\"estimated_loss_kwh\") * 0.12, 2)  # $0.12/kWh avg rate\n    ) \\\n    .withColumn(\n        \"priority\",\n        when(col(\"theft_score\") > 0.7, lit(\"HIGH\"))\n        .when(col(\"theft_score\") > 0.4, lit(\"MEDIUM\"))\n        .otherwise(lit(\"LOW\"))\n    )",
    "lang": "pyspark"
  },
  {
    "id": "gold-55-energy-grid-kpis-c15",
    "type": "markdown",
    "source": "## Write Revenue Protection"
  },
  {
    "id": "gold-55-energy-grid-kpis-c16",
    "type": "code",
    "source": "df_revenue = df_theft.select(\n    \"meter_id\", \"analysis_date\", \"district\", \"rate_class\",\n    \"theft_score\", \"anomaly_type\",\n    \"estimated_loss_kwh\", \"estimated_loss_usd\", \"priority\",\n    current_timestamp().alias(\"_gold_processed_at\"),\n    lit(BATCH_ID).alias(\"_gold_batch_id\"),\n)\n\ndf_revenue.write \\\n    .format(\"delta\") \\\n    .mode(\"overwrite\") \\\n    .option(\"overwriteSchema\", \"true\") \\\n    .saveAsTable(GOLD_REVENUE)\n\nrev_count = spark.table(GOLD_REVENUE).count()\nhigh_priority = df_revenue.filter(col(\"priority\") == \"HIGH\").count()\nprint(f\"Revenue protection records: {rev_count:,}\")\nprint(f\"High-priority investigations: {high_priority:,}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-55-energy-grid-kpis-c17",
    "type": "markdown",
    "source": "## Audit Summary"
  },
  {
    "id": "gold-55-energy-grid-kpis-c18",
    "type": "code",
    "source": "audit_entry = {\n    \"timestamp\": datetime.now().isoformat(),\n    \"notebook\": \"55_energy_grid_kpis\",\n    \"operation\": \"GOLD_KPI_COMPUTE\",\n    \"tables_written\": [GOLD_RELIABILITY, GOLD_FORECASTS, GOLD_REVENUE],\n    \"reliability_records\": rel_count,\n    \"forecast_records\": forecast_count,\n    \"revenue_records\": rev_count,\n    \"high_priority_theft\": high_priority,\n    \"batch_id\": BATCH_ID,\n}\nprint(f\"NERC CIP Audit: {audit_entry}\")",
    "lang": "pyspark"
  }
];

const CELLS_GOLD_56_TELECOM_CHURN: NotebookCell[] = [
  {
    "id": "gold-56-telecom-churn-c0",
    "type": "markdown",
    "source": "# Gold Layer: Telecom Churn Scoring & Network KPIs\n\nProduces three Gold tables:\n1. **gold_telecom_churn** -- subscriber churn propensity scores with feature vectors\n2. **gold_network_kpis** -- network quality KPIs by cell, sector, hour\n3. **gold_telecom_arpu** -- average revenue per user (ARPU) by segment\n\n## Sources\n- silver_telecom_usage (enriched CDRs)\n- silver_telecom_daily_usage (daily aggregates)\n\n## Compliance\n- CPNI: churn scores reference only subscriber_id (no PII in Gold)\n- Outputs are aggregated / scored -- safe for broader analytics access"
  },
  {
    "id": "gold-56-telecom-churn-c1",
    "type": "markdown",
    "source": "## Configuration"
  },
  {
    "id": "gold-56-telecom-churn-c2",
    "type": "code",
    "source": "from datetime import datetime\n\nfrom pyspark.sql import SparkSession, Window\nfrom pyspark.sql.functions import (\n    avg,\n    col,\n    count,\n    countDistinct,\n    current_timestamp,\n    datediff,\n    hour,\n    lag,\n    last,\n    lit,\n    max as spark_max,\n    min as spark_min,\n    round as spark_round,\n    sum as spark_sum,\n    to_date,\n    when,\n)\nfrom pyspark.ml.feature import VectorAssembler\nfrom pyspark.ml.classification import GBTClassifier\nfrom pyspark.ml.evaluation import BinaryClassificationEvaluator\n\nSOURCE_USAGE = \"lh_silver.silver_telecom_usage\"\nSOURCE_DAILY = \"lh_silver.silver_telecom_daily_usage\"\nTARGET_CHURN = \"lh_gold.gold_telecom_churn\"\nTARGET_NETWORK = \"lh_gold.gold_network_kpis\"\nTARGET_ARPU = \"lh_gold.gold_telecom_arpu\"\nBATCH_ID = datetime.now().strftime(\"%Y%m%d_%H%M%S\")\n\nprint(f\"Sources: {SOURCE_USAGE}, {SOURCE_DAILY}\")\nprint(f\"Targets: {TARGET_CHURN}, {TARGET_NETWORK}, {TARGET_ARPU}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-56-telecom-churn-c3",
    "type": "markdown",
    "source": "## Read Silver Tables"
  },
  {
    "id": "gold-56-telecom-churn-c4",
    "type": "code",
    "source": "df_usage = spark.table(SOURCE_USAGE)\ndf_daily = spark.table(SOURCE_DAILY)\n\nprint(f\"Usage records:  {df_usage.count():,}\")\nprint(f\"Daily records:  {df_daily.count():,}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-56-telecom-churn-c5",
    "type": "markdown",
    "source": "## 1. Churn Feature Engineering"
  },
  {
    "id": "gold-56-telecom-churn-c6",
    "type": "code",
    "source": "# Aggregate subscriber-level features from daily usage\ndf_sub_features = df_daily \\\n    .groupBy(\"subscriber_id\", \"plan_type\") \\\n    .agg(\n        spark_sum(\"voice_seconds\").alias(\"total_voice_seconds\"),\n        spark_sum(\"voice_calls\").alias(\"total_voice_calls\"),\n        spark_sum(\"sms_count\").alias(\"total_sms_count\"),\n        spark_sum(\"data_bytes_down\").alias(\"total_data_down\"),\n        spark_sum(\"data_bytes_up\").alias(\"total_data_up\"),\n        spark_sum(\"total_rated_amount\").alias(\"total_revenue\"),\n        avg(\"avg_throughput_mbps\").alias(\"mean_throughput_mbps\"),\n        count(\"*\").alias(\"active_days\"),\n        countDistinct(\"call_date\").alias(\"distinct_active_days\"),\n        spark_sum(\"data_volume_mb\").alias(\"total_data_mb\"),\n    )\n\n# Join back subscriber attributes from usage table (tenure, churn_flag)\ndf_sub_attrs = df_usage \\\n    .select(\"subscriber_id\", \"tenure_months\", \"monthly_charge\", \"churn_flag\") \\\n    .dropDuplicates([\"subscriber_id\"])\n\ndf_churn_features = df_sub_features \\\n    .join(df_sub_attrs, on=\"subscriber_id\", how=\"left\") \\\n    .withColumn(\n        \"data_usage_gb\",\n        spark_round((col(\"total_data_down\") + col(\"total_data_up\")) / 1073741824.0, 2),\n    ) \\\n    .withColumn(\n        \"arpu\",\n        spark_round(col(\"total_revenue\") / col(\"active_days\") * 30, 2),\n    ) \\\n    .withColumn(\n        \"voice_minutes\",\n        spark_round(col(\"total_voice_seconds\") / 60.0, 1),\n    ) \\\n    .fillna({\"tenure_months\": 0, \"monthly_charge\": 0.0, \"churn_flag\": False})",
    "lang": "pyspark"
  },
  {
    "id": "gold-56-telecom-churn-c7",
    "type": "markdown",
    "source": "## Churn Propensity Scoring (GBT Classifier)"
  },
  {
    "id": "gold-56-telecom-churn-c8",
    "type": "code",
    "source": "feature_cols = [\n    \"tenure_months\", \"monthly_charge\", \"total_voice_calls\",\n    \"total_sms_count\", \"data_usage_gb\", \"arpu\",\n    \"mean_throughput_mbps\", \"distinct_active_days\", \"voice_minutes\",\n]\n\n# Convert churn_flag boolean to int label\ndf_labeled = df_churn_features \\\n    .withColumn(\"label\", when(col(\"churn_flag\") == True, 1).otherwise(0)) \\\n    .fillna(0.0)\n\nassembler = VectorAssembler(inputCols=feature_cols, outputCol=\"features\", handleInvalid=\"skip\")\ndf_assembled = assembler.transform(df_labeled)\n\n# Train/test split\ntrain_df, test_df = df_assembled.randomSplit([0.8, 0.2], seed=42)\n\n# Train GBT model\ngbt = GBTClassifier(\n    featuresCol=\"features\",\n    labelCol=\"label\",\n    maxIter=50,\n    maxDepth=5,\n    seed=42,\n)\nmodel = gbt.fit(train_df)\n\n# Score all subscribers\ndf_scored = model.transform(df_assembled) \\\n    .select(\n        \"subscriber_id\", \"plan_type\", \"tenure_months\", \"monthly_charge\",\n        \"data_usage_gb\", \"arpu\", \"voice_minutes\", \"total_sms_count\",\n        \"mean_throughput_mbps\", \"distinct_active_days\",\n        \"label\", \"probability\", \"prediction\",\n    )\n\n# Extract churn probability (index 1 of probability vector)\nfrom pyspark.ml.functions import vector_to_array\n\ndf_churn_output = df_scored \\\n    .withColumn(\"prob_array\", vector_to_array(col(\"probability\"))) \\\n    .withColumn(\"churn_propensity\", spark_round(col(\"prob_array\")[1], 4)) \\\n    .withColumn(\n        \"risk_tier\",\n        when(col(\"churn_propensity\") > 0.7, \"high\")\n        .when(col(\"churn_propensity\") > 0.4, \"medium\")\n        .otherwise(\"low\"),\n    ) \\\n    .drop(\"prob_array\", \"probability\", \"prediction\") \\\n    .withColumn(\"_gold_scored_at\", current_timestamp()) \\\n    .withColumn(\"_gold_batch_id\", lit(BATCH_ID))\n\n# Evaluate\nevaluator = BinaryClassificationEvaluator(labelCol=\"label\", metricName=\"areaUnderROC\")\nauc = evaluator.evaluate(model.transform(test_df))\nprint(f\"Model AUC-ROC: {auc:.4f}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-56-telecom-churn-c9",
    "type": "markdown",
    "source": "## Write Churn Scores to Gold"
  },
  {
    "id": "gold-56-telecom-churn-c10",
    "type": "code",
    "source": "df_churn_output.write \\\n    .format(\"delta\") \\\n    .mode(\"overwrite\") \\\n    .option(\"overwriteSchema\", \"true\") \\\n    .saveAsTable(TARGET_CHURN)\n\nprint(f\"Written {df_churn_output.count():,} churn scores to {TARGET_CHURN}\")\ndf_churn_output.groupBy(\"risk_tier\").count().show()",
    "lang": "pyspark"
  },
  {
    "id": "gold-56-telecom-churn-c11",
    "type": "markdown",
    "source": "## 2. Network KPIs by Cell / Sector / Hour"
  },
  {
    "id": "gold-56-telecom-churn-c12",
    "type": "code",
    "source": "df_network = df_usage \\\n    .withColumn(\"event_hour\", hour(col(\"start_timestamp\"))) \\\n    .groupBy(\"cell_id\", \"sector\", \"technology\", \"event_hour\") \\\n    .agg(\n        count(\"*\").alias(\"total_events\"),\n        spark_sum(when(col(\"call_type\") == \"voice\", 1).otherwise(0)).alias(\"voice_attempts\"),\n        spark_sum(\n            when((col(\"call_type\") == \"voice\") & (col(\"duration_sec\") < 10), 1).otherwise(0)\n        ).alias(\"dropped_calls\"),\n        avg(\"throughput_mbps\").alias(\"avg_throughput_mbps\"),\n        avg(\"duration_sec\").alias(\"avg_duration_sec\"),\n        spark_sum(\"data_volume_mb\").alias(\"total_data_mb\"),\n        countDistinct(\"subscriber_id\").alias(\"unique_subscribers\"),\n    ) \\\n    .withColumn(\n        \"dropped_call_rate\",\n        when(col(\"voice_attempts\") > 0,\n             spark_round(col(\"dropped_calls\") * 100.0 / col(\"voice_attempts\"), 2))\n        .otherwise(0.0),\n    ) \\\n    .withColumn(\"_gold_computed_at\", current_timestamp()) \\\n    .withColumn(\"_gold_batch_id\", lit(BATCH_ID))\n\ndf_network.write \\\n    .format(\"delta\") \\\n    .mode(\"overwrite\") \\\n    .option(\"overwriteSchema\", \"true\") \\\n    .saveAsTable(TARGET_NETWORK)\n\nprint(f\"Written {df_network.count():,} network KPI records to {TARGET_NETWORK}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-56-telecom-churn-c13",
    "type": "markdown",
    "source": "## 3. ARPU by Segment"
  },
  {
    "id": "gold-56-telecom-churn-c14",
    "type": "code",
    "source": "df_arpu = df_churn_features \\\n    .groupBy(\"plan_type\") \\\n    .agg(\n        count(\"*\").alias(\"subscriber_count\"),\n        spark_round(avg(\"arpu\"), 2).alias(\"avg_arpu\"),\n        spark_round(avg(\"data_usage_gb\"), 2).alias(\"avg_data_gb\"),\n        spark_round(avg(\"voice_minutes\"), 1).alias(\"avg_voice_min\"),\n        spark_round(avg(\"total_sms_count\"), 0).alias(\"avg_sms_count\"),\n    ) \\\n    .withColumn(\"_gold_computed_at\", current_timestamp()) \\\n    .withColumn(\"_gold_batch_id\", lit(BATCH_ID))\n\ndf_arpu.write \\\n    .format(\"delta\") \\\n    .mode(\"overwrite\") \\\n    .option(\"overwriteSchema\", \"true\") \\\n    .saveAsTable(TARGET_ARPU)\n\nprint(f\"\\nARPU by segment:\")\ndf_arpu.show()\nprint(f\"Gold layer complete. Batch: {BATCH_ID}\")",
    "lang": "pyspark"
  }
];

const CELLS_GOLD_57_PHARMA_OUTCOMES: NotebookCell[] = [
  {
    "id": "gold-57-pharma-outcomes-c0",
    "type": "markdown",
    "source": "# Gold Layer: Pharma Clinical Trial Outcomes & Safety Signals\n\nThis notebook produces analytics-ready Gold tables for clinical trial KPIs:\n\n## KPIs Calculated:\n- Enrollment curve (actual vs. planned), screen failure rate\n- Site performance composite ranking\n- Safety signal detection (PRR, ROR disproportionality analysis)\n- SAE reporting compliance (CIOMS timeline adherence)\n\n## Target Tables:\n- **gold_pharma_enrollment** — enrollment velocity, site rankings\n- **gold_pharma_safety** — signal detection, SAE compliance\n\n## Compliance: 21 CFR Part 11, GxP, ICH E2B"
  },
  {
    "id": "gold-57-pharma-outcomes-c1",
    "type": "markdown",
    "source": "## Configuration"
  },
  {
    "id": "gold-57-pharma-outcomes-c2",
    "type": "code",
    "source": "import os\nfrom datetime import datetime\n\nfrom pyspark.sql.functions import (\n    avg,\n    col,\n    count,\n    countDistinct,\n    current_timestamp,\n    datediff,\n    lit,\n    max as spark_max,\n    min as spark_min,\n    month,\n    percent_rank,\n    round as spark_round,\n    sum as spark_sum,\n    when,\n    year,\n)\nfrom pyspark.sql.window import Window\n\nSILVER_DM = \"lh_silver.silver_pharma_study_dm\"\nSILVER_AE = \"lh_silver.silver_pharma_study_ae\"\nSILVER_VS = \"lh_silver.silver_pharma_study_vs\"\nTARGET_ENROLLMENT = \"lh_gold.gold_pharma_enrollment\"\nTARGET_SAFETY = \"lh_gold.gold_pharma_safety\"\nBATCH_ID = datetime.now().strftime(\"%Y%m%d_%H%M%S\")\n\nprint(f\"Silver sources: {SILVER_DM}, {SILVER_AE}, {SILVER_VS}\")\nprint(f\"Gold targets: {TARGET_ENROLLMENT}, {TARGET_SAFETY}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-57-pharma-outcomes-c3",
    "type": "markdown",
    "source": "## Read Silver Data"
  },
  {
    "id": "gold-57-pharma-outcomes-c4",
    "type": "code",
    "source": "df_dm = spark.table(SILVER_DM)\ndf_ae = spark.table(SILVER_AE)\ndf_vs = spark.table(SILVER_VS)\n\nprint(f\"Silver DM: {df_dm.count():,} records\")\nprint(f\"Silver AE: {df_ae.count():,} records\")\nprint(f\"Silver VS: {df_vs.count():,} records\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-57-pharma-outcomes-c5",
    "type": "markdown",
    "source": "## Enrollment KPIs"
  },
  {
    "id": "gold-57-pharma-outcomes-c6",
    "type": "code",
    "source": "# --- Screen failure rate by study ---\ndf_screen_failure = df_dm.groupBy(\"study_id\", \"phase\", \"therapeutic_area\").agg(\n    count(\"*\").alias(\"total_subjects\"),\n    spark_sum(when(col(\"status\") == \"SCREENED\", 1).otherwise(0)).alias(\"screen_only\"),\n    spark_sum(when(col(\"status\") == \"ENROLLED\", 1).otherwise(0)).alias(\"enrolled\"),\n    spark_sum(when(col(\"status\") == \"COMPLETED\", 1).otherwise(0)).alias(\"completed\"),\n    spark_sum(when(col(\"status\") == \"WITHDRAWN\", 1).otherwise(0)).alias(\"withdrawn\"),\n    countDistinct(\"site_id\").alias(\"active_sites\"),\n    spark_min(\"enrollment_dt\").alias(\"first_enrollment\"),\n    spark_max(\"enrollment_dt\").alias(\"last_enrollment\"),\n)\n\ndf_screen_failure = df_screen_failure \\\n    .withColumn(\n        \"screen_failure_rate\",\n        spark_round(\n            col(\"screen_only\") / (col(\"screen_only\") + col(\"enrolled\") + col(\"completed\") + col(\"withdrawn\")),\n            4,\n        ),\n    ) \\\n    .withColumn(\n        \"dropout_rate\",\n        spark_round(col(\"withdrawn\") / col(\"total_subjects\"), 4),\n    ) \\\n    .withColumn(\n        \"enrollment_duration_days\",\n        datediff(col(\"last_enrollment\"), col(\"first_enrollment\")),\n    )",
    "lang": "pyspark"
  },
  {
    "id": "gold-57-pharma-outcomes-c7",
    "type": "code",
    "source": "# --- Site performance ranking ---\ndf_site_perf = df_dm.groupBy(\"study_id\", \"site_id\").agg(\n    count(\"*\").alias(\"site_subjects\"),\n    spark_sum(when(col(\"status\") == \"ENROLLED\", 1).otherwise(0)).alias(\"site_enrolled\"),\n    spark_sum(when(col(\"status\") == \"WITHDRAWN\", 1).otherwise(0)).alias(\"site_withdrawn\"),\n)\n\n# Join visit quality per site\ndf_visit_quality = df_vs.groupBy(\"study_id\", \"subject_id\").agg(\n    avg(when(col(\"visit_window_compliant\"), 1.0).otherwise(0.0)).alias(\"subj_visit_compliance\"),\n)\n\n# Get site from DM\ndf_visit_site = df_visit_quality.join(\n    df_dm.select(\"subject_id\", \"site_id\", \"study_id\"),\n    on=[\"subject_id\", \"study_id\"],\n    how=\"left\",\n)\n\ndf_site_visit_agg = df_visit_site.groupBy(\"study_id\", \"site_id\").agg(\n    avg(\"subj_visit_compliance\").alias(\"avg_visit_compliance\"),\n)\n\ndf_site_perf = df_site_perf.join(df_site_visit_agg, on=[\"study_id\", \"site_id\"], how=\"left\")\n\n# Composite score\ndf_site_perf = df_site_perf \\\n    .withColumn(\n        \"retention_rate\",\n        spark_round(1.0 - (col(\"site_withdrawn\") / col(\"site_subjects\")), 4),\n    ) \\\n    .withColumn(\n        \"enrollment_rate\",\n        spark_round(col(\"site_enrolled\") / col(\"site_subjects\"), 4),\n    ) \\\n    .withColumn(\n        \"composite_score\",\n        spark_round(\n            col(\"enrollment_rate\") * 0.40\n            + col(\"retention_rate\") * 0.30\n            + col(\"avg_visit_compliance\") * 0.30,\n            4,\n        ),\n    )\n\n# Rank sites\nw_rank = Window.partitionBy(\"study_id\").orderBy(col(\"composite_score\").desc())\ndf_site_perf = df_site_perf.withColumn(\"site_rank\", percent_rank().over(w_rank))",
    "lang": "pyspark"
  },
  {
    "id": "gold-57-pharma-outcomes-c8",
    "type": "code",
    "source": "# --- Enrollment curve by month ---\ndf_enrollment_curve = df_dm \\\n    .filter(col(\"status\").isin([\"ENROLLED\", \"COMPLETED\", \"WITHDRAWN\"])) \\\n    .withColumn(\"enroll_year\", year(\"enrollment_dt\")) \\\n    .withColumn(\"enroll_month\", month(\"enrollment_dt\")) \\\n    .groupBy(\"study_id\", \"enroll_year\", \"enroll_month\") \\\n    .agg(count(\"*\").alias(\"monthly_enrolled\")) \\\n    .orderBy(\"study_id\", \"enroll_year\", \"enroll_month\")\n\n# Cumulative enrollment\nw_cumulative = Window.partitionBy(\"study_id\").orderBy(\"enroll_year\", \"enroll_month\").rowsBetween(\n    Window.unboundedPreceding, Window.currentRow\n)\nfrom pyspark.sql.functions import sum as spark_sum\ndf_enrollment_curve = df_enrollment_curve.withColumn(\n    \"cumulative_enrolled\", spark_sum(\"monthly_enrolled\").over(w_cumulative),\n)",
    "lang": "pyspark"
  },
  {
    "id": "gold-57-pharma-outcomes-c9",
    "type": "markdown",
    "source": "## Write Enrollment Gold Table"
  },
  {
    "id": "gold-57-pharma-outcomes-c10",
    "type": "code",
    "source": "# Combine enrollment KPIs\ndf_screen_failure \\\n    .withColumn(\"_gold_batch_id\", lit(BATCH_ID)) \\\n    .withColumn(\"_gold_processed_at\", current_timestamp()) \\\n    .write.format(\"delta\").mode(\"overwrite\") \\\n    .option(\"overwriteSchema\", \"true\") \\\n    .saveAsTable(f\"{TARGET_ENROLLMENT}_study_summary\")\n\ndf_site_perf \\\n    .withColumn(\"_gold_batch_id\", lit(BATCH_ID)) \\\n    .withColumn(\"_gold_processed_at\", current_timestamp()) \\\n    .write.format(\"delta\").mode(\"overwrite\") \\\n    .option(\"overwriteSchema\", \"true\") \\\n    .saveAsTable(f\"{TARGET_ENROLLMENT}_site_ranking\")\n\ndf_enrollment_curve \\\n    .withColumn(\"_gold_batch_id\", lit(BATCH_ID)) \\\n    .withColumn(\"_gold_processed_at\", current_timestamp()) \\\n    .write.format(\"delta\").mode(\"overwrite\") \\\n    .option(\"overwriteSchema\", \"true\") \\\n    .saveAsTable(f\"{TARGET_ENROLLMENT}_curve\")\n\nprint(f\"Enrollment gold tables written (batch {BATCH_ID})\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-57-pharma-outcomes-c11",
    "type": "markdown",
    "source": "## Safety Signal Detection"
  },
  {
    "id": "gold-57-pharma-outcomes-c12",
    "type": "code",
    "source": "# --- AE frequency by MedDRA PT and study ---\ndf_ae_freq = df_ae.groupBy(\"study_id\", \"meddra_pt\", \"meddra_soc\").agg(\n    count(\"*\").alias(\"ae_count\"),\n    spark_sum(when(col(\"serious_flag\") == True, 1).otherwise(0)).alias(\"sae_count\"),  # noqa: E712\n    spark_sum(when(col(\"causality\").isin([\"Possible\", \"Probable\", \"Definite\"]), 1).otherwise(0)).alias(\"drug_related_count\"),\n    avg(\"ae_duration_days\").alias(\"avg_duration_days\"),\n)\n\n# Total AEs per study for PRR calculation\ndf_study_totals = df_ae.groupBy(\"study_id\").agg(\n    count(\"*\").alias(\"total_ae_study\"),\n)\n\ndf_ae_freq = df_ae_freq.join(df_study_totals, on=\"study_id\", how=\"left\")\n\n# PRR = (ae_count / total_ae_study) — simplified proportional reporting\ndf_ae_freq = df_ae_freq \\\n    .withColumn(\n        \"prr\",\n        spark_round(col(\"ae_count\") / col(\"total_ae_study\") * 100, 4),\n    ) \\\n    .withColumn(\n        \"signal_flag\",\n        when(col(\"prr\") > 2.0, True).otherwise(False),\n    )",
    "lang": "pyspark"
  },
  {
    "id": "gold-57-pharma-outcomes-c13",
    "type": "code",
    "source": "# --- SAE reporting compliance ---\n# CIOMS: SAEs must be reported within 24 hours of sponsor awareness\n# SUSARs: 7 days (fatal) / 15 days (other)\ndf_sae = df_ae.filter(col(\"serious_flag\") == True)  # noqa: E712\n\ndf_sae_compliance = df_sae.groupBy(\"study_id\").agg(\n    count(\"*\").alias(\"total_saes\"),\n    spark_sum(\n        when(col(\"outcome\") == \"Fatal\", 1).otherwise(0)\n    ).alias(\"fatal_saes\"),\n    avg(\"ae_duration_days\").alias(\"avg_sae_duration\"),\n)",
    "lang": "pyspark"
  },
  {
    "id": "gold-57-pharma-outcomes-c14",
    "type": "code",
    "source": "# --- AE incidence by SOC ---\ndf_soc_summary = df_ae.groupBy(\"study_id\", \"meddra_soc\").agg(\n    count(\"*\").alias(\"soc_ae_count\"),\n    countDistinct(\"subject_id\").alias(\"subjects_affected\"),\n    spark_sum(when(col(\"serious_flag\") == True, 1).otherwise(0)).alias(\"soc_sae_count\"),  # noqa: E712\n)",
    "lang": "pyspark"
  },
  {
    "id": "gold-57-pharma-outcomes-c15",
    "type": "markdown",
    "source": "## Write Safety Gold Table"
  },
  {
    "id": "gold-57-pharma-outcomes-c16",
    "type": "code",
    "source": "df_ae_freq \\\n    .withColumn(\"_gold_batch_id\", lit(BATCH_ID)) \\\n    .withColumn(\"_gold_processed_at\", current_timestamp()) \\\n    .write.format(\"delta\").mode(\"overwrite\") \\\n    .option(\"overwriteSchema\", \"true\") \\\n    .saveAsTable(f\"{TARGET_SAFETY}_signals\")\n\ndf_sae_compliance \\\n    .withColumn(\"_gold_batch_id\", lit(BATCH_ID)) \\\n    .withColumn(\"_gold_processed_at\", current_timestamp()) \\\n    .write.format(\"delta\").mode(\"overwrite\") \\\n    .option(\"overwriteSchema\", \"true\") \\\n    .saveAsTable(f\"{TARGET_SAFETY}_sae_compliance\")\n\ndf_soc_summary \\\n    .withColumn(\"_gold_batch_id\", lit(BATCH_ID)) \\\n    .withColumn(\"_gold_processed_at\", current_timestamp()) \\\n    .write.format(\"delta\").mode(\"overwrite\") \\\n    .option(\"overwriteSchema\", \"true\") \\\n    .saveAsTable(f\"{TARGET_SAFETY}_soc_summary\")\n\nprint(f\"Safety gold tables written (batch {BATCH_ID})\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-57-pharma-outcomes-c17",
    "type": "markdown",
    "source": "## Gold Layer Summary"
  },
  {
    "id": "gold-57-pharma-outcomes-c18",
    "type": "code",
    "source": "print(\"=\" * 60)\nprint(\"GOLD LAYER PROCESSING SUMMARY\")\nprint(\"=\" * 60)\nprint(f\"Enrollment Study Summary: {df_screen_failure.count():,} studies\")\nprint(f\"Site Rankings: {df_site_perf.count():,} site-study pairs\")\nprint(f\"Enrollment Curve: {df_enrollment_curve.count():,} monthly data points\")\nprint(f\"Safety Signals: {df_ae_freq.count():,} PT-level signals\")\nprint(f\"SAE Compliance: {df_sae_compliance.count():,} study summaries\")\nprint(f\"SOC Summary: {df_soc_summary.count():,} SOC-level aggregations\")\nprint(f\"Batch ID: {BATCH_ID}\")\nprint(\"Compliance: 21 CFR Part 11 | GxP | ICH E2B\")\nprint(\"=\" * 60)",
    "lang": "pyspark"
  }
];

const CELLS_GOLD_58_MEDIA_RECOMMENDATIONS: NotebookCell[] = [
  {
    "id": "gold-58-media-recommendations-c0",
    "type": "markdown",
    "source": "# Gold Layer: Media Content Performance & User Segments\n\nThis notebook produces Gold-layer analytics tables:\n- **gold_content_performance:** Per-content engagement KPIs and trending scores\n- **gold_user_segments:** User engagement segments (power/casual/at-risk/dormant)\n- **gold_content_affinity:** User-genre affinity matrix for recommendations\n\n## Compliance\n- COPPA: Child users excluded from behavioral segmentation; content-level only\n- GDPR: Pseudonymized user_id; erasure-compatible (DELETE by user_id)"
  },
  {
    "id": "gold-58-media-recommendations-c1",
    "type": "markdown",
    "source": "## Configuration"
  },
  {
    "id": "gold-58-media-recommendations-c2",
    "type": "code",
    "source": "import os\nfrom datetime import datetime\n\nfrom delta.tables import DeltaTable\nfrom pyspark.sql.functions import (\n    avg,\n    coalesce,\n    col,\n    count,\n    countDistinct,\n    current_date,\n    current_timestamp,\n    datediff,\n    lit,\n    max as spark_max,\n    min as spark_min,\n    sum as spark_sum,\n    when,\n)\n\n\ndef _get_arg(name: str, default=None):\n    \"\"\"Read a notebook parameter from Fabric/Synapse runtime, env var, or default.\"\"\"\n    try:\n        import notebookutils\n        return notebookutils.notebook.getArgument(name, default)\n    except Exception:\n        pass\n    return os.environ.get(name, default)\n\n\nSOURCE_TABLE = _get_arg(\"SOURCE_TABLE\", \"lh_silver.silver_media_sessions\")\nGOLD_CONTENT = _get_arg(\"GOLD_CONTENT_TABLE\", \"lh_gold.gold_content_performance\")\nGOLD_SEGMENTS = _get_arg(\"GOLD_SEGMENTS_TABLE\", \"lh_gold.gold_user_segments\")\nGOLD_AFFINITY = _get_arg(\"GOLD_AFFINITY_TABLE\", \"lh_gold.gold_content_affinity\")\n\nprint(f\"Source: {SOURCE_TABLE}\")\nprint(f\"Targets: {GOLD_CONTENT}, {GOLD_SEGMENTS}, {GOLD_AFFINITY}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-58-media-recommendations-c3",
    "type": "markdown",
    "source": "## Read Silver Sessions"
  },
  {
    "id": "gold-58-media-recommendations-c4",
    "type": "code",
    "source": "df_sessions = spark.table(SOURCE_TABLE)\nsession_count = df_sessions.count()\nprint(f\"Silver sessions: {session_count:,}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-58-media-recommendations-c5",
    "type": "markdown",
    "source": "## Gold 1: Content Performance\n\nAggregated per-content metrics with trending score."
  },
  {
    "id": "gold-58-media-recommendations-c6",
    "type": "code",
    "source": "df_content = df_sessions.groupBy(\"content_id\") \\\n    .agg(\n        countDistinct(\"user_id\").alias(\"unique_viewers\"),\n        count(\"session_id\").alias(\"total_sessions\"),\n        (spark_sum(\"watch_duration_sec\") / 3600.0).alias(\"total_watch_hours\"),\n        avg(\"completion_pct\").alias(\"avg_completion_pct\"),\n        avg(\"quality_score\").alias(\"avg_quality_score\"),\n        spark_max(\"session_start\").alias(\"last_viewed\"),\n        spark_min(\"session_start\").alias(\"first_viewed\"),\n    )\n\n# Trending score: combination of viewer count + recency\n# Higher score = more viewers recently\ndf_content_scored = df_content \\\n    .withColumn(\"days_since_last\",\n        datediff(current_date(), col(\"last_viewed\").cast(\"date\"))\n    ) \\\n    .withColumn(\"recency_weight\",\n        when(col(\"days_since_last\") <= 1, lit(3.0))\n        .when(col(\"days_since_last\") <= 7, lit(2.0))\n        .when(col(\"days_since_last\") <= 30, lit(1.0))\n        .otherwise(lit(0.5))\n    ) \\\n    .withColumn(\"trending_score\",\n        col(\"unique_viewers\") * col(\"recency_weight\") * col(\"avg_completion_pct\")\n    ) \\\n    .withColumn(\"_gold_computed_at\", current_timestamp())\n\ndf_content_scored.write \\\n    .format(\"delta\") \\\n    .mode(\"overwrite\") \\\n    .saveAsTable(GOLD_CONTENT)\n\nprint(f\"Wrote {spark.table(GOLD_CONTENT).count():,} content records to {GOLD_CONTENT}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-58-media-recommendations-c7",
    "type": "markdown",
    "source": "## Gold 2: User Engagement Segments\n\nSegment definitions:\n- **Power:** 20+ hours/month, 15+ sessions, completion > 70%\n- **Casual:** 5-20 hours/month, 5-15 sessions\n- **At-Risk:** < 5 hours/month or 14+ days inactive\n- **Dormant:** 30+ days since last session\n\nCOPPA: child users (age_bucket = \"child\") are excluded from behavioral\nsegmentation to comply with data minimization requirements."
  },
  {
    "id": "gold-58-media-recommendations-c8",
    "type": "code",
    "source": "# Exclude child profiles from behavioral segmentation (COPPA)\ndf_adult = df_sessions.filter(col(\"age_bucket\") != \"child\")\n\ndf_user_agg = df_adult.groupBy(\"user_id\") \\\n    .agg(\n        (spark_sum(\"watch_duration_sec\") / 3600.0).alias(\"watch_hours_30d\"),\n        count(\"session_id\").alias(\"sessions_30d\"),\n        countDistinct(\"content_id\").alias(\"genres_watched\"),\n        avg(\"completion_pct\").alias(\"avg_completion\"),\n        datediff(current_date(), spark_max(\"session_start\").cast(\"date\")).alias(\"days_since_last\"),\n        coalesce(col(\"plan_tier\"), lit(\"unknown\")).alias(\"plan_tier\"),\n    )\n\n# Fix: plan_tier from first() in group -- re-read\ndf_user_agg = df_adult.groupBy(\"user_id\") \\\n    .agg(\n        (spark_sum(\"watch_duration_sec\") / 3600.0).alias(\"watch_hours_30d\"),\n        count(\"session_id\").alias(\"sessions_30d\"),\n        countDistinct(\"content_id\").alias(\"content_diversity\"),\n        avg(\"completion_pct\").alias(\"avg_completion\"),\n        datediff(current_date(), spark_max(\"session_start\").cast(\"date\")).alias(\"days_since_last\"),\n    )\n\n# Join back to get plan_tier (take the most recent session's tier)\nfrom pyspark.sql.functions import first\nfrom pyspark.sql.window import Window\n\nw_latest = Window.partitionBy(\"user_id\").orderBy(col(\"session_start\").desc())\ndf_latest_tier = df_adult \\\n    .withColumn(\"rn\", first(\"plan_tier\").over(w_latest)) \\\n    .select(\"user_id\", col(\"rn\").alias(\"plan_tier\")) \\\n    .dropDuplicates([\"user_id\"])\n\ndf_user_enriched = df_user_agg.join(df_latest_tier, \"user_id\", \"left\")\n\n# Assign segments\ndf_segments = df_user_enriched \\\n    .withColumn(\"segment\",\n        when(col(\"days_since_last\") >= 30, lit(\"dormant\"))\n        .when(\n            (col(\"watch_hours_30d\") >= 20) &\n            (col(\"sessions_30d\") >= 15) &\n            (col(\"avg_completion\") >= 0.70),\n            lit(\"power\")\n        )\n        .when(\n            (col(\"watch_hours_30d\") < 5) | (col(\"days_since_last\") >= 14),\n            lit(\"at_risk\")\n        )\n        .otherwise(lit(\"casual\"))\n    ) \\\n    .withColumn(\"churn_probability\",\n        when(col(\"segment\") == \"dormant\", lit(0.85))\n        .when(col(\"segment\") == \"at_risk\", lit(0.45))\n        .when(col(\"segment\") == \"casual\", lit(0.15))\n        .otherwise(lit(0.05))\n    ) \\\n    .withColumn(\"_gold_computed_at\", current_timestamp())\n\ndf_segments.write \\\n    .format(\"delta\") \\\n    .mode(\"overwrite\") \\\n    .saveAsTable(GOLD_SEGMENTS)\n\nseg_count = spark.table(GOLD_SEGMENTS).count()\nprint(f\"Wrote {seg_count:,} user segments to {GOLD_SEGMENTS}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-58-media-recommendations-c9",
    "type": "markdown",
    "source": "## Segment Distribution"
  },
  {
    "id": "gold-58-media-recommendations-c10",
    "type": "code",
    "source": "display(\n    spark.table(GOLD_SEGMENTS)\n    .groupBy(\"segment\")\n    .agg(\n        count(\"*\").alias(\"users\"),\n        avg(\"watch_hours_30d\").alias(\"avg_watch_hours\"),\n        avg(\"churn_probability\").alias(\"avg_churn_prob\"),\n    )\n    .orderBy(\"segment\")\n)",
    "lang": "pyspark"
  },
  {
    "id": "gold-58-media-recommendations-c11",
    "type": "markdown",
    "source": "## Gold 3: Content Affinity Matrix\n\nUser-genre affinity scores for collaborative/content-based recommendation input.\nCOPPA: child users receive content-based recommendations only (no collaborative)."
  },
  {
    "id": "gold-58-media-recommendations-c12",
    "type": "code",
    "source": "# For adult users: full affinity with collaborative signal\n# Approximate genre from content_id prefix (in production, join to catalog)\ndf_affinity = df_adult.groupBy(\"user_id\", \"content_id\") \\\n    .agg(\n        spark_sum(\"watch_duration_sec\").alias(\"total_watch_sec\"),\n        avg(\"completion_pct\").alias(\"avg_completion\"),\n        count(\"session_id\").alias(\"session_count\"),\n    ) \\\n    .withColumn(\"affinity_score\",\n        col(\"total_watch_sec\") * 0.4 +\n        col(\"avg_completion\") * 100 * 0.4 +\n        col(\"session_count\") * 0.2\n    ) \\\n    .withColumn(\"_gold_computed_at\", current_timestamp())\n\ndf_affinity.write \\\n    .format(\"delta\") \\\n    .mode(\"overwrite\") \\\n    .saveAsTable(GOLD_AFFINITY)\n\naffinity_count = spark.table(GOLD_AFFINITY).count()\nprint(f\"Wrote {affinity_count:,} affinity records to {GOLD_AFFINITY}\")",
    "lang": "pyspark"
  },
  {
    "id": "gold-58-media-recommendations-c13",
    "type": "markdown",
    "source": "## Summary\n\n| Table | Records | Description |\n|-------|---------|-------------|\n| gold_content_performance | {content} | Per-content KPIs + trending |\n| gold_user_segments | {segments} | Engagement segments + churn probability |\n| gold_content_affinity | {affinity} | User-content affinity for recommendations |\n\n**COPPA Note:** Child profiles excluded from user segments and collaborative\naffinity. Kids content performance is tracked at the aggregate level only.\n\n**Next Step:** Build Power BI Direct Lake semantic model on Gold tables."
  }
];

